import { Injectable, signal } from '@angular/core';

export interface NumberStat {
  number: number;
  count: number;
  frequency: number; // percentage
  status: 'hot' | 'neutral' | 'cold';
}

@Injectable({
  providedIn: 'root'
})
export class LottoStatsService {
  private readonly TOTAL_NUMBERS = 49;
  private readonly DRAW_SIZE = 6;
  private readonly HISTORY_SIZE = 2000; // Simulate 2000 historical draws

  // State
  stats = signal<NumberStat[]>([]);
  lastDraws = signal<number[][]>([]);

  constructor() {
    this.runSimulation();
  }

  /**
   * Symuluje historyczne losowania, aby zbudować bazę danych do analizy.
   * W prawdziwej aplikacji te dane pochodziłyby z API Lotto.
   */
  runSimulation() {
    const counts = new Map<number, number>();
    const history: number[][] = [];

    // Initialize counts
    for (let i = 1; i <= this.TOTAL_NUMBERS; i++) {
      counts.set(i, 0);
    }

    // Simulate draws
    for (let i = 0; i < this.HISTORY_SIZE; i++) {
      const draw = this.generateRandomDraw();
      history.push(draw);
      draw.forEach(num => {
        counts.set(num, (counts.get(num) || 0) + 1);
      });
    }

    // Calculate stats
    const statsArray: NumberStat[] = [];
    counts.forEach((count, num) => {
      statsArray.push({
        number: num,
        count: count,
        frequency: count / this.HISTORY_SIZE,
        status: 'neutral'
      });
    });

    // Determine Hot/Cold based on percentiles
    statsArray.sort((a, b) => b.count - a.count);

    const hotThreshold = Math.floor(this.TOTAL_NUMBERS * 0.2); // Top 20%
    const coldThreshold = Math.floor(this.TOTAL_NUMBERS * 0.8); // Bottom 20%

    statsArray.forEach((stat, index) => {
      if (index < hotThreshold) stat.status = 'hot';
      else if (index > coldThreshold) stat.status = 'cold';
    });

    // Sort back by number for display consistency or keep sorted by freq? 
    // Let's keep sorted by number for lookup, but we can access sorted via computed in component
    this.stats.set(statsArray.sort((a, b) => a.number - b.number));
    this.lastDraws.set(history.slice(-10)); // Keep last 10 for display
  }

  /**
   * Algorytm hybrydowy:
   * 3 liczby "Gorące" (najczęściej występujące)
   * 2 liczby "Neutralne" (średnia statystyczna)
   * 1 liczba "Zimna" (rzadko występująca - teoria "prawa serii")
   */
  generateSmartPrediction(): { numbers: number[], logic: string[] } {
    const allStats = [...this.stats()].sort((a, b) => b.count - a.count); // Sort by frequency desc

    const hotPool = allStats.slice(0, 15);
    const neutralPool = allStats.slice(15, 35);
    const coldPool = allStats.slice(35);

    const selection = new Set<number>();
    const logic: string[] = [];

    // Pick 3 Hot
    while (selection.size < 3) {
      const pick = this.pickRandomFrom(hotPool);
      if (!selection.has(pick.number)) {
        selection.add(pick.number);
      }
    }
    logic.push(`Wybrano 3 liczby z grupy "Gorących" (występujących najczęściej w ostatnich ${this.HISTORY_SIZE} losowaniach). Statystycznie utrzymują trend.`);

    // Pick 2 Neutral
    while (selection.size < 5) {
      const pick = this.pickRandomFrom(neutralPool);
      if (!selection.has(pick.number)) {
        selection.add(pick.number);
      }
    }
    logic.push(`Dobrano 2 liczby "Neutralne" dla stabilizacji wariancji.`);

    // Pick 1 Cold
    while (selection.size < 6) {
      const pick = this.pickRandomFrom(coldPool);
      if (!selection.has(pick.number)) {
        selection.add(pick.number);
      }
    }
    logic.push(`Dodano 1 liczbę "Zimną". Teoretycznie prawdopodobieństwo jej wylosowania rośnie z czasem (powrót do średniej).`);

    return {
      numbers: Array.from(selection).sort((a, b) => a - b),
      logic
    };
  }

  private pickRandomFrom(pool: NumberStat[]): NumberStat {
    const idx = Math.floor(Math.random() * pool.length);
    return pool[idx];
  }

  private generateRandomDraw(): number[] {
    const numbers = new Set<number>();
    while (numbers.size < this.DRAW_SIZE) {
      numbers.add(Math.floor(Math.random() * this.TOTAL_NUMBERS) + 1);
    }
    return Array.from(numbers);
  }
}

import { Injectable } from '@angular/core';
import { GoogleGenAI } from '@google/genai';
import { NumberStat } from './lotto-stats.service';

@Injectable({
  providedIn: 'root'
})
export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env['API_KEY'] });
  }

  async explainPrediction(prediction: number[], stats: NumberStat[]): Promise<string> {
    const model = this.ai.models;

    // Prepare concise context
    const predictionStats = prediction.map(num => {
      const s = stats.find(stat => stat.number === num);
      return `${num} (Status: ${s?.status}, Wystąpień: ${s?.count})`;
    }).join(', ');

    const prompt = `
      Jesteś ekspertem Data Science i probabilistyki. 
      Analizujesz wyniki symulacji Lotto (6 z 49).

      Oto wytypowane liczby przez algorytm hybrydowy: [${predictionStats}].

      Zadanie:
      Wydaj krótki, profesjonalny komentarz (maksymalnie 3 zdania) w języku polskim, dlaczego taki miks (Gorące/Zimne liczby) jest popularną strategią w grach losowych, mimo że każde losowanie jest niezależne. Użyj terminologii statystycznej (np. wariancja, rozkład normalny, prawo wielkich liczb). Bądź rzeczowy.
    `;

    try {
      const result = await model.generateContent({
        model: 'gemini-2.5-flash',
        contents: prompt
      });
      return result.text;
    } catch (error) {
      console.error('Gemini error:', error);
      return 'Nie udało się wygenerować analizy AI. Sprawdź konfigurację klucza API.';
    }
  }
}

