import { Injectable, signal, computed, effect } from '@angular/core';

export type GameType = 'lotto' | 'mini' | 'euro';
export type DataSource = 'simulation' | 'manual';

export interface GameConfig {
  id: GameType;
  name: string;
  totalNumbers: number;
  drawSize: number;
  color: string;
}

export interface NumberStat {
  number: number;
  count: number;
  frequency: number; // percentage
  status: 'hot' | 'neutral' | 'cold';
}

export interface Coupon {
  id: string;
  type: 'ai' | 'manual'; // Distinguish source
  date: Date;
  gameId: GameType;
  gameName: string;
  numbers: number[];
  drawResult: number[] | null; // Null if not checked yet
  matches: number | null;
}

@Injectable({
  providedIn: 'root'
})
export class LottoStatsService {
  private readonly HISTORY_SIZE = 2000;

  readonly games: GameConfig[] = [
    { id: 'lotto', name: 'Lotto', totalNumbers: 49, drawSize: 6, color: 'text-yellow-500' },
    { id: 'mini', name: 'Mini Lotto', totalNumbers: 42, drawSize: 5, color: 'text-blue-400' },
    { id: 'euro', name: 'Eurojackpot (5/50)', totalNumbers: 50, drawSize: 5, color: 'text-orange-500' }
  ];

  // State
  activeGameId = signal<GameType>('lotto');
  dataSource = signal<DataSource>('simulation');
  manualHotNumbers = signal<Set<number>>(new Set());

  stats = signal<NumberStat[]>([]);
  savedCoupons = signal<Coupon[]>([]);

  activeGameConfig = computed(() => 
    this.games.find(g => g.id === this.activeGameId())!
  );

  constructor() {
    // Re-calculate stats whenever dependencies change
    effect(() => {
        this.calculateStats();
    });
  }

  setGame(gameId: GameType) {
    this.activeGameId.set(gameId);
    // When switching games, clear manual selection to avoid confusion (indices differ)
    this.manualHotNumbers.set(new Set()); 
  }

  setDataSource(source: DataSource) {
    this.dataSource.set(source);
  }

  toggleManualHotNumber(num: number) {
    const current = new Set(this.manualHotNumbers());
    if (current.has(num)) {
      current.delete(num);
    } else {
      current.add(num);
    }
    this.manualHotNumbers.set(current);
  }

  private calculateStats() {
    if (this.dataSource() === 'simulation') {
        this.runSimulation();
    } else {
        this.applyManualStats();
    }
  }

  private applyManualStats() {
    const config = this.activeGameConfig();
    const statsArray: NumberStat[] = [];
    const manualHot = this.manualHotNumbers();

    // Assign weights: Selected = 100, Others = random 0-50 to create "Cold" noise
    for (let i = 1; i <= config.totalNumbers; i++) {
        let count = 0;
        if (manualHot.has(i)) {
            count = 100; // Force to top
        } else {
            count = Math.floor(Math.random() * 50); // Random noise for neutral/cold
        }

        statsArray.push({
            number: i,
            count: count,
            frequency: count / 100, // normalized-ish
            status: 'neutral'
        });
    }

    // Sort by count desc
    statsArray.sort((a, b) => b.count - a.count);

    // Assign status labels
    const hotThreshold = Math.floor(config.totalNumbers * 0.2);
    const coldThreshold = Math.floor(config.totalNumbers * 0.8);

    statsArray.forEach((stat, index) => {
      // If manually selected, force status hot even if outside threshold (visual feedback)
      if (manualHot.has(stat.number)) {
          stat.status = 'hot';
      } else {
        if (index < hotThreshold && !manualHot.has(stat.number)) stat.status = 'hot'; // Fill remaining hot spots if user selected few
        else if (index > coldThreshold) stat.status = 'cold';
        else stat.status = 'neutral';
      }
    });

    this.stats.set(statsArray.sort((a, b) => a.number - b.number));
  }

  private runSimulation() {
    const config = this.activeGameConfig();
    const counts = new Map<number, number>();

    // Initialize counts
    for (let i = 1; i <= config.totalNumbers; i++) {
      counts.set(i, 0);
    }

    // Simulate draws
    for (let i = 0; i < this.HISTORY_SIZE; i++) {
      const draw = this.generateRandomDraw(config.totalNumbers, config.drawSize);
      draw.forEach(num => {
        counts.set(num, (counts.get(num) || 0) + 1);
      });
    }

    // Calculate stats
    const statsArray: NumberStat[] = [];
    counts.forEach((count, num) => {
      statsArray.push({
        number: num,
        count: count,
        frequency: count / this.HISTORY_SIZE,
        status: 'neutral'
      });
    });

    statsArray.sort((a, b) => b.count - a.count);

    const hotThreshold = Math.floor(config.totalNumbers * 0.2);
    const coldThreshold = Math.floor(config.totalNumbers * 0.8);

    statsArray.forEach((stat, index) => {
      if (index < hotThreshold) stat.status = 'hot';
      else if (index > coldThreshold) stat.status = 'cold';
    });

    this.stats.set(statsArray.sort((a, b) => a.number - b.number));
  }

  generateSmartPrediction(): { numbers: number[], logic: string[] } {
    const config = this.activeGameConfig();
    const allStats = [...this.stats()].sort((a, b) => b.count - a.count);

    const selection = new Set<number>();
    const logic: string[] = [];

    // Determine pools
    // If manual data, 'hot' are the ones with count=100 or top sorted
    const hotPool = allStats.filter(s => s.status === 'hot');
    const coldPool = allStats.filter(s => s.status === 'cold');
    const neutralPool = allStats.filter(s => s.status === 'neutral');

    // Strategy distribution depends on draw size
    const hotTarget = Math.ceil(config.drawSize * 0.5); 
    const coldTarget = 1;

    // Pick Hot
    // If user provided manual numbers, this prioritizes them
    let attempts = 0;
    while (selection.size < hotTarget && hotPool.length > 0 && attempts < 20) {
      const pick = this.pickRandomFrom(hotPool);
      if (!selection.has(pick.number)) selection.add(pick.number);
      attempts++;
    }

    if (this.dataSource() === 'manual') {
        logic.push(`Priorytet: Twoje zdefiniowane "Gorące Liczby".`);
    } else {
        logic.push(`Wybrano ${hotTarget} liczb z grupy "Gorących" (trend wzrostowy).`);
    }

    // Pick Cold
    attempts = 0;
    while (selection.size < hotTarget + coldTarget && coldPool.length > 0 && attempts < 20) {
      const pick = this.pickRandomFrom(coldPool);
      if (!selection.has(pick.number)) selection.add(pick.number);
      attempts++;
    }
    logic.push(`Dodano ${coldTarget} liczbę "Zimną" (oczekiwany powrót do średniej).`);

    // Fill with Neutral or whatever is left
    attempts = 0;
    while (selection.size < config.drawSize && attempts < 100) {
      // Fallback pool if neutral is empty
      const pool = neutralPool.length > 0 ? neutralPool : allStats;
      const pick = this.pickRandomFrom(pool);
      if (!selection.has(pick.number)) selection.add(pick.number);
      attempts++;
    }
    logic.push(`Uzupełniono liczbami neutralnymi dla balansu.`);

    return {
      numbers: Array.from(selection).sort((a, b) => a - b),
      logic
    };
  }

  saveCoupon(numbers: number[], type: 'ai' | 'manual') {
    const newCoupon: Coupon = {
      id: crypto.randomUUID(),
      type: type,
      date: new Date(),
      gameId: this.activeGameId(),
      gameName: this.activeGameConfig().name,
      numbers: [...numbers].sort((a, b) => a - b),
      drawResult: null,
      matches: null
    };
    this.savedCoupons.update(prev => [newCoupon, ...prev]);
  }

  checkCouponResult(couponId: string) {
    const config = this.activeGameConfig();
    // Simulate a "Real" draw happening now
    const draw = this.generateRandomDraw(config.totalNumbers, config.drawSize).sort((a, b) => a - b);

    this.savedCoupons.update(coupons => coupons.map(c => {
      if (c.id === couponId) {
        const matches = c.numbers.filter(n => draw.includes(n)).length;
        return { ...c, drawResult: draw, matches };
      }
      return c;
    }));
  }

  clearHistory() {
    this.savedCoupons.set([]);
  }

  private pickRandomFrom(pool: NumberStat[]): NumberStat {
    if (pool.length === 0) return this.stats()[Math.floor(Math.random() * this.stats().length)];
    const idx = Math.floor(Math.random() * pool.length);
    return pool[idx];
  }

  private generateRandomDraw(total: number, size: number): number[] {
    const numbers = new Set<number>();
    while (numbers.size < size) {
      numbers.add(Math.floor(Math.random() * total) + 1);
    }
    return Array.from(numbers);
  }
}

