  // Higher weight = historically "Hot" number
  private readonly REAL_STATS_WEIGHTS: Record<GameType, Record<number, number>> = {
    lotto: {
      17: 150, 34: 145, 24: 142, 6: 140, 21: 138, 4: 135, // Historically frequent
