  }

  setDataSource(source: DataSource) {
    this.dataSource.set(source);
  }

  toggleManualHotNumber(num: number) {
    const current = new Set(this.manualHotNumbers());
    if (current.has(num)) {
      current.delete(num);
    } else {
      current.add(num);
    }
    this.manualHotNumbers.set(current);
  }

  private calculateStats() {
    switch (this.dataSource()) {
      case 'simulation':
        this.runSimulation();
        break;
      case 'manual':
        this.applyManualStats();
        break;
      case 'real_history':
        this.loadRealHistoryStats();
        break;
    }
  }

  private loadRealHistoryStats() {
    const config = this.activeGameConfig();
    const statsArray: NumberStat[] = [];
    const weights = this.REAL_STATS_WEIGHTS[this.activeGameId()] || {};

    // Base standard count for numbers not in the "Top/Bottom" list
    const BASE_COUNT = 100;

    for (let i = 1; i <= config.totalNumbers; i++) {
        // Use defined weight or base count + small random variance for realism
        let count = weights[i] || (BASE_COUNT + Math.floor(Math.random() * 20 - 10));

        // Add a "recent trend" noise to make it not static
        count += Math.floor(Math.random() * 5);

        statsArray.push({
            number: i,
            count: count,
            frequency: count / 1000, // normalized rough
            status: 'neutral'
        });
    }

    // Sort by count desc
    statsArray.sort((a, b) => b.count - a.count);
    this.assignHotColdStatus(statsArray, config.totalNumbers);
    this.stats.set(statsArray.sort((a, b) => a.number - b.number));
  }

  private applyManualStats() {
    const config = this.activeGameConfig();
    const statsArray: NumberStat[] = [];
    const manualHot = this.manualHotNumbers();

    // Assign weights: Selected = 100, Others = random 0-50 to create "Cold" noise
    for (let i = 1; i <= config.totalNumbers; i++) {
        let count = 0;
        if (manualHot.has(i)) {
            count = 100; // Force to top
        } else {
            count = Math.floor(Math.random() * 50); // Random noise for neutral/cold
        }

        statsArray.push({
            number: i,
            count: count,
            frequency: count / 100, // normalized-ish
            status: 'neutral'
        });
    }

    // Sort by count desc
    statsArray.sort((a, b) => b.count - a.count);

    // Assign status labels (Custom logic for Manual: strictly follow selection)
    const hotThreshold = Math.floor(config.totalNumbers * 0.2);
    const coldThreshold = Math.floor(config.totalNumbers * 0.8);

    statsArray.forEach((stat, index) => {
      // If manually selected, force status hot
      if (manualHot.has(stat.number)) {
          stat.status = 'hot';
      } else {
        if (index < hotThreshold && !manualHot.has(stat.number)) stat.status = 'hot'; 
        else if (index > coldThreshold) stat.status = 'cold';
        else stat.status = 'neutral';
      }
    });

    this.stats.set(statsArray.sort((a, b) => a.number - b.number));
  }

  private runSimulation() {
    const config = this.activeGameConfig();
