    let validDraws = 0;
    const lines = text.split('\n');

    // Format expected: "7139. 02.01.2025 2,12,17,24,42,43"
    // Regex matches lines ending in numbers separated by commas
    const regex = /(\d{1,2}(,\d{1,2}){4,})/; 

    for (const line of lines) {
        const match = line.match(regex);
        if (match) {
            const numbersPart = match[0];
            const nums = numbersPart.split(',').map(n => parseInt(n.trim()));

            // Validate numbers for current game
            const config = this.activeGameConfig();
            const validNums = nums.filter(n => !isNaN(n) && n >= 1 && n <= config.totalNumbers);

            if (validNums.length >= config.drawSize - 2) { // Allow some leniency
                validDraws++;
                validNums.forEach(n => {
                    counts[n] = (counts[n] || 0) + 1;
                });
            }
        }
    }

    if (validDraws > 0) {
        this.customDataCounts.set(counts);
        this.customDataTotalDraws.set(validDraws);
        this.setDataSource('custom_import');
        return true;
    }
    return false;
  }

  private calculateStats() {
    switch (this.dataSource()) {
      case 'simulation':
        this.runSimulation();
        break;
      case 'manual':
        this.applyManualStats();
        break;
      case 'real_history':
        this.loadRealHistoryStats();
        break;
      case 'custom_import':
        this.loadCustomImportStats();
        break;
    }
  }

  private loadCustomImportStats() {
    const config = this.activeGameConfig();
    const statsArray: NumberStat[] = [];
    const counts = this.customDataCounts();
    const total = this.customDataTotalDraws();

    for (let i = 1; i <= config.totalNumbers; i++) {
        const count = counts[i] || 0;
        statsArray.push({
            number: i,
            count: count,
            frequency: total > 0 ? count / total : 0,
            status: 'neutral'
        });
    }

    statsArray.sort((a, b) => b.count - a.count);
    this.assignHotColdStatus(statsArray, config.totalNumbers);
    this.stats.set(statsArray.sort((a, b) => a.number - b.number));
  }

  private loadRealHistoryStats() {
    const config = this.activeGameConfig();
    const statsArray: NumberStat[] = [];
    const historicalData = this.REAL_DATA_2000_2024[this.activeGameId()] || {};
    const totalDrawsEstimate = 3500;

    for (let i = 1; i <= config.totalNumbers; i++) {
        let count = historicalData[i] || 100;
        count += Math.floor(Math.random() * 3); 

        statsArray.push({
            number: i,
            count: count,
            frequency: count / totalDrawsEstimate, 
            status: 'neutral'
        });
    }

    statsArray.sort((a, b) => b.count - a.count);
    this.assignHotColdStatus(statsArray, config.totalNumbers);
    this.stats.set(statsArray.sort((a, b) => a.number - b.number));
  }

  private applyManualStats() {
    const config = this.activeGameConfig();
    const statsArray: NumberStat[] = [];
    const manualHot = this.manualHotNumbers();

    for (let i = 1; i <= config.totalNumbers; i++) {
        let count = 0;
        if (manualHot.has(i)) {
            count = 100;
        } else {
            count = Math.floor(Math.random() * 50);
        }

        statsArray.push({
            number: i,
            count: count,
            frequency: count / 100,
            status: 'neutral'
        });
    }

    statsArray.sort((a, b) => b.count - a.count);

    const hotThreshold = Math.floor(config.totalNumbers * 0.2);
    const coldThreshold = Math.floor(config.totalNumbers * 0.8);

    statsArray.forEach((stat, index) => {
      if (manualHot.has(stat.number)) {
          stat.status = 'hot';
      } else {
        if (index < hotThreshold && !manualHot.has(stat.number)) stat.status = 'hot'; 
        else if (index > coldThreshold) stat.status = 'cold';
        else stat.status = 'neutral';
      }
    });

    this.stats.set(statsArray.sort((a, b) => a.number - b.number));
  }

  private runSimulation() {
    const config = this.activeGameConfig();
    const counts = new Map<number, number>();

    for (let i = 1; i <= config.totalNumbers; i++) {
      counts.set(i, 0);
    }

    for (let i = 0; i < this.HISTORY_SIZE; i++) {
      const draw = this.generateRandomDraw(config.totalNumbers, config.drawSize);
      draw.forEach(num => {
        counts.set(num, (counts.get(num) || 0) + 1);
      });
    }

    const statsArray: NumberStat[] = [];
    counts.forEach((count, num) => {
      statsArray.push({
        number: num,
        count: count,
        frequency: count / this.HISTORY_SIZE,
        status: 'neutral'
      });
    });

    statsArray.sort((a, b) => b.count - a.count);
    this.assignHotColdStatus(statsArray, config.totalNumbers);
    this.stats.set(statsArray.sort((a, b) => a.number - b.number));
  }

  private assignHotColdStatus(statsArray: NumberStat[], totalNumbers: number) {
    const hotThreshold = Math.floor(totalNumbers * 0.2);
    const coldThreshold = Math.floor(totalNumbers * 0.8);

    statsArray.forEach((stat, index) => {
      if (index < hotThreshold) stat.status = 'hot';
      else if (index > coldThreshold) stat.status = 'cold';
      else stat.status = 'neutral';
    });
  }

  generateSmartPrediction(): { numbers: number[], logic: string[] } {
    const config = this.activeGameConfig();
    const allStats = [...this.stats()].sort((a, b) => b.count - a.count);

    const selection = new Set<number>();
    const logic: string[] = [];

    const hotPool = allStats.filter(s => s.status === 'hot');
    const coldPool = allStats.filter(s => s.status === 'cold');
    const neutralPool = allStats.filter(s => s.status === 'neutral');

    const hotTarget = Math.ceil(config.drawSize * 0.5); 
    const coldTarget = 1;

    let attempts = 0;
    while (selection.size < hotTarget && hotPool.length > 0 && attempts < 20) {
      const pick = this.pickRandomFrom(hotPool);
      if (!selection.has(pick.number)) selection.add(pick.number);
      attempts++;
    }

    if (this.dataSource() === 'manual') {
        logic.push(`Priorytet: Twoje zdefiniowane "Gorące Liczby".`);
    } else if (this.dataSource() === 'real_history') {
        logic.push(`Baza statystyczna 2000-2024: Wybrano ${hotTarget} liczb o najwyższym współczynniku wystąpień.`);
    } else if (this.dataSource() === 'custom_import') {
        logic.push(`Baza Własna (Import): Analiza ${this.customDataTotalDraws()} wklejonych losowań.`);
    } else {
        logic.push(`Wybrano ${hotTarget} liczb z grupy "Gorących" (trend wzrostowy).`);
    }

    attempts = 0;
    while (selection.size < hotTarget + coldTarget && coldPool.length > 0 && attempts < 20) {
      const pick = this.pickRandomFrom(coldPool);
      if (!selection.has(pick.number)) selection.add(pick.number);
      attempts++;
    }
    logic.push(`Dodano ${coldTarget} liczbę "Zimną" (statystyczne wyrównanie).`);

    attempts = 0;
    while (selection.size < config.drawSize && attempts < 100) {
      const pool = neutralPool.length > 0 ? neutralPool : allStats;
      const pick = this.pickRandomFrom(pool);
      if (!selection.has(pick.number)) selection.add(pick.number);
      attempts++;
    }
    logic.push(`Uzupełniono liczbami neutralnymi dla balansu.`);

    return {
      numbers: Array.from(selection).sort((a, b) => a - b),
      logic
    };
  }

  saveCoupon(numbers: number[], type: 'ai' | 'manual') {
    const newCoupon: Coupon = {
      id: crypto.randomUUID(),
      type: type,
      date: new Date(),
      gameId: this.activeGameId(),
      gameName: this.activeGameConfig().name,
      numbers: [...numbers].sort((a, b) => a - b),
      drawResult: null,
      matches: null,
      isRealCheck: false
    };
    this.savedCoupons.update(prev => [newCoupon, ...prev]);
  }

  checkCouponResult(couponId: string) {
    const config = this.activeGameConfig();
    const draw = this.generateRandomDraw(config.totalNumbers, config.drawSize).sort((a, b) => a - b);

    this.savedCoupons.update(coupons => coupons.map(c => {
      if (c.id === couponId) {
        const matches = c.numbers.filter(n => draw.includes(n)).length;
        return { ...c, drawResult: draw, matches, isRealCheck: false };
      }
      return c;
    }));
  }

  checkCouponsAgainstRealNumbers(winningNumbers: number[]) {
    const sortedWinning = [...winningNumbers].sort((a, b) => a - b);
    const currentGameId = this.activeGameId();

    this.savedCoupons.update(coupons => coupons.map(c => {
      if (c.gameId === currentGameId) {
        const matches = c.numbers.filter(n => sortedWinning.includes(n)).length;
        return { 
          ...c, 
          drawResult: sortedWinning, 
          matches,
          isRealCheck: true 
        };
      }
      return c;
    }));
  }

  clearHistory() {
    this.savedCoupons.set([]);
  }

  private pickRandomFrom(pool: NumberStat[]): NumberStat {
    if (pool.length === 0) return this.stats()[Math.floor(Math.random() * this.stats().length)];
    const idx = Math.floor(Math.random() * pool.length);
    return pool[idx];
  }

  private generateRandomDraw(total: number, size: number): number[] {
    const numbers = new Set<number>();
    while (numbers.size < size) {
      numbers.add(Math.floor(Math.random() * total) + 1);
    }
    return Array.from(numbers);
  }
}

import { Component, signal, inject, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { LottoStatsService, GameType } from './services/lotto-stats.service';
import { GeminiService } from './services/gemini.service';
import { HistogramComponent } from './components/histogram.component';

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [CommonModule, HistogramComponent],
  templateUrl: './app.component.html'
})
export class AppComponent {
  lottoService = inject(LottoStatsService);
  geminiService = inject(GeminiService);

  // UI State
  currentView = signal<'analyze' | 'history' | 'settings'>('analyze');
  isManualMode = signal(false);

  // Real Check Mode State (in History)
  isCheckMode = signal(false);
  winningNumbersSelection = signal<Set<number>>(new Set());

  // Import Data State
  importText = signal('');
  importSuccess = signal(false);

  // AI Logic State
  loading = signal(false);
  prediction = signal<number[]>([]);
  logicSteps = signal<string[]>([]);
  aiExplanation = signal<string>('');

  // Manual Entry State
  manualNumbers = signal<Set<number>>(new Set());

  // Feedback state
  linkCopied = signal(false);

  // Computed helper for grid generation
  gridNumbers = computed(() => {
    return Array.from({ length: this.lottoService.activeGameConfig().totalNumbers }, (_, i) => i + 1);
  });

  isManualComplete = computed(() => {
    return this.manualNumbers().size === this.lottoService.activeGameConfig().drawSize;
  });

  // For Checking Mode
  isWinningSelectionComplete = computed(() => {
    return this.winningNumbersSelection().size === this.lottoService.activeGameConfig().drawSize;
  });

  switchGame(gameId: GameType) {
    this.lottoService.setGame(gameId);
    this.resetState();
    this.isCheckMode.set(false);
    this.winningNumbersSelection.set(new Set());
  }

  toggleManualMode() {
    this.isManualMode.update(v => !v);
    this.manualNumbers.set(new Set()); // Reset selections on toggle
  }

  // Toggle for the Real Check Mode in History
  toggleCheckMode() {
    this.isCheckMode.update(v => !v);
    this.winningNumbersSelection.set(new Set());
  }

  toggleManualNumber(num: number) {
    const current = new Set(this.manualNumbers());
    const limit = this.lottoService.activeGameConfig().drawSize;

    if (current.has(num)) {
      current.delete(num);
    } else {
      if (current.size < limit) {
        current.add(num);
      }
    }
    this.manualNumbers.set(current);
  }

  toggleWinningNumber(num: number) {
    const current = new Set(this.winningNumbersSelection());
    const limit = this.lottoService.activeGameConfig().drawSize;

    if (current.has(num)) {
      current.delete(num);
    } else {
      if (current.size < limit) {
        current.add(num);
      }
    }
    this.winningNumbersSelection.set(current);
  }

  saveManualCoupon() {
    if (this.isManualComplete()) {
      this.lottoService.saveCoupon(Array.from(this.manualNumbers()), 'manual');
      this.currentView.set('history');
      this.isManualMode.set(false);
      this.manualNumbers.set(new Set());
    }
  }

  confirmRealCheck() {
    if (this.isWinningSelectionComplete()) {
      this.lottoService.checkCouponsAgainstRealNumbers(Array.from(this.winningNumbersSelection()));
      this.isCheckMode.set(false);
      this.winningNumbersSelection.set(new Set());
    }
  }

  onPasteResults(event: ClipboardEvent) {
    const clipboardData = event.clipboardData;
    const pastedText = clipboardData?.getData('text') || '';

    // Attempt to extract numbers from pasted text (e.g. "2, 12, 15...")
    const numbers = pastedText.split(/[\s,]+/)
      .map(s => parseInt(s.trim()))
      .filter(n => !isNaN(n));

    const config = this.lottoService.activeGameConfig();
    const newSelection = new Set<number>();

    // Take only valid numbers up to draw limit
    for (const num of numbers) {
      if (num >= 1 && num <= config.totalNumbers && newSelection.size < config.drawSize) {
        newSelection.add(num);
      }
    }

    if (newSelection.size > 0) {
      this.winningNumbersSelection.set(newSelection);
    }
  }

  onImportTextChange(event: Event) {
    const target = event.target as HTMLTextAreaElement;
    this.importText.set(target.value);
  }

  processImport() {
    const success = this.lottoService.processImportedData(this.importText());
    if (success) {
        this.importSuccess.set(true);
        this.importText.set('');
        setTimeout(() => this.importSuccess.set(false), 3000);
        // Switch to analyze view to show results
        this.currentView.set('analyze');
    } else {
        alert('Nie udało się zaimportować danych. Sprawdź format.');
    }
  }

  private resetState() {
    this.prediction.set([]);
    this.logicSteps.set([]);
    this.aiExplanation.set('');
    this.manualNumbers.set(new Set());
    this.isManualMode.set(false);
  }

  async generatePrediction() {
    this.loading.set(true);
    this.prediction.set([]); 
    this.aiExplanation.set('');
    this.logicSteps.set([]);
    this.isManualMode.set(false);

    await new Promise(resolve => setTimeout(resolve, 600));

    const result = this.lottoService.generateSmartPrediction();

    this.prediction.set(result.numbers);
    this.logicSteps.set(result.logic);
    this.loading.set(false);

    const explanation = await this.geminiService.explainPrediction(
      result.numbers, 
      this.lottoService.stats(),
      this.lottoService.activeGameConfig().name
    );

    this.aiExplanation.set(explanation);
  }

  saveCurrentPrediction() {
    if (this.prediction().length > 0) {
      this.lottoService.saveCoupon(this.prediction(), 'ai');
      this.currentView.set('history');
    }
  }

  toggleFullscreen() {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(err => {
        console.error('Error attempting to enable fullscreen:', err);
      });
    } else {
      document.exitFullscreen();
    }
  }

  clearHistory() {
    if (confirm('Czy na pewno chcesz usunąć całą historię kuponów?')) {
      this.lottoService.clearHistory();
    }
  }

  shareApp() {
    const url = window.location.href;
    const shareData = {
      title: 'Lotto Data Scientist',
      text: 'Sprawdź swoje szanse w Lotto z analizą AI!',
      url: url
    };

    if (navigator.share) {
      navigator.share(shareData).catch((err) => console.log('Error sharing:', err));
    } else {
      navigator.clipboard.writeText(url).then(() => {
        this.linkCopied.set(true);
        setTimeout(() => this.linkCopied.set(false), 2000);
      }).catch(err => {
        console.error('Could not copy text: ', err);
        alert('Skopiuj ten link: ' + url);
      });
    }
  }
}

import { Injectable, signal, computed, effect } from '@angular/core';

export type GameType = 'lotto' | 'mini' | 'euro';
export type DataSource = 'simulation' | 'manual' | 'real_history' | 'custom_import' | 'expert_trend';

export interface GameConfig {
  id: GameType;
  name: string;
  totalNumbers: number;
  drawSize: number;
  color: string;
}

export interface NumberStat {
  number: number;
  count: number;
  frequency: number; // percentage
  status: 'hot' | 'neutral' | 'cold';
}

export interface Coupon {
  id: string;
  type: 'ai' | 'manual';
  date: Date;
  gameId: GameType;
  gameName: string;
  numbers: number[];
  drawResult: number[] | null;
  matches: number | null;
  isRealCheck?: boolean;
}

@Injectable({
  providedIn: 'root'
})
export class LottoStatsService {
  private readonly HISTORY_SIZE = 2000;

  readonly games: GameConfig[] = [
    { id: 'lotto', name: 'Lotto', totalNumbers: 49, drawSize: 6, color: 'text-yellow-500' },
    { id: 'mini', name: 'Mini Lotto', totalNumbers: 42, drawSize: 5, color: 'text-blue-400' },
    { id: 'euro', name: 'Eurojackpot (5/50)', totalNumbers: 50, drawSize: 5, color: 'text-orange-500' }
