  /**
   * EXPERT KNOWLEDGE BASE (2021-2025 Trends)
   * Specific to Polish Lotto (1-49).
   */
  private readonly EXPERT_DATA_LOTTO = {
    hot: [4, 30, 14, 2, 44, 24], // "Dobra passa"
    cold: [43, 48, 33, 1],       // "Śpiące"
    pairs: [                     // "Association Rules"
        [4, 30],
        [17, 21],
        [24, 29],
        [15, 25]
