  };

  /**
   * REAL STATISTICAL DATA BASE (2000-2024 Snapshot)
   */
  private readonly REAL_DATA_2000_2024: Record<GameType, Record<number, number>> = {
    lotto: {
      1: 430, 2: 442, 3: 450, 4: 480, 5: 440, 6: 495, 7: 435, 8: 445, 9: 438, 10: 452,
      11: 425, 12: 430, 13: 460, 14: 445, 15: 455, 16: 450, 17: 512, 18: 465, 19: 440, 20: 438,
      21: 485, 22: 432, 23: 445, 24: 490, 25: 450, 26: 448, 27: 455, 28: 460, 29: 442, 30: 435,
