      11: 310, 12: 305, 13: 315, 14: 320, 15: 330, 16: 310, 17: 315, 18: 345, 19: 310, 20: 315,
      21: 350, 22: 305, 23: 310, 24: 325, 25: 315, 26: 320, 27: 310, 28: 340, 29: 305, 30: 335,
      31: 345, 32: 310, 33: 300, 34: 320, 35: 325, 36: 355, 37: 310, 38: 320, 39: 315, 40: 310,
