    this.dataSource.set(source);
  }

  toggleManualHotNumber(num: number) {
    const current = new Set(this.manualHotNumbers());
    if (current.has(num)) {
      current.delete(num);
    } else {
      current.add(num);
    }
    this.manualHotNumbers.set(current);
  }

  // PARSER for User Data
  processImportedData(text: string): boolean {
    const counts: Record<number, number> = {};
    let validDraws = 0;
    const lines = text.split('\n');
    const regex = /(\d{1,2}(,\d{1,2}){4,})/; 

    for (const line of lines) {
        const match = line.match(regex);
        if (match) {
            const numbersPart = match[0];
            const nums = numbersPart.split(',').map(n => parseInt(n.trim()));
            const config = this.activeGameConfig();
            const validNums = nums.filter(n => !isNaN(n) && n >= 1 && n <= config.totalNumbers);

            if (validNums.length >= config.drawSize - 2) { 
                validDraws++;
                validNums.forEach(n => {
                    counts[n] = (counts[n] || 0) + 1;
                });
            }
        }
    }

    if (validDraws > 0) {
        this.customDataCounts.set(counts);
        this.customDataTotalDraws.set(validDraws);
        this.setDataSource('custom_import');
        return true;
    }
    return false;
  }

  private calculateStats() {
    switch (this.dataSource()) {
      case 'simulation':
        this.runSimulation();
        break;
      case 'manual':
        this.applyManualStats();
        break;
      case 'real_history':
        this.loadRealHistoryStats();
        break;
      case 'custom_import':
        this.loadCustomImportStats();
        break;
      case 'expert_trend':
        this.loadExpertTrendStats();
        break;
    }
  }

  private loadExpertTrendStats() {
    const config = this.activeGameConfig();
    const statsArray: NumberStat[] = [];

    // Base weight for all numbers
    const baseCount = 50;

    for (let i = 1; i <= config.totalNumbers; i++) {
        let count = baseCount;
        let status: 'hot' | 'neutral' | 'cold' = 'neutral';

        // Apply Expert Knowledge specific to the active game
        if (this.activeGameId() === 'lotto') {
            if (this.EXPERT_DATA_LOTTO.hot.includes(i)) {
                count = 100; 
                status = 'hot';
            } else if (this.EXPERT_DATA_LOTTO.cold.includes(i)) {
                count = 10; 
                status = 'cold';
            } else {
                count += Math.floor(Math.random() * 20) - 10;
            }
        } else if (this.activeGameId() === 'mini') {
            if (this.EXPERT_DATA_MINI.hot.includes(i)) {
                count = 100; 
                status = 'hot';
            } else if (this.EXPERT_DATA_MINI.cold.includes(i)) {
                count = 10; 
                status = 'cold';
            } else {
                count += Math.floor(Math.random() * 20) - 10;
            }
        } else if (this.activeGameId() === 'euro') {
             if (this.EXPERT_DATA_EURO.hot.includes(i)) {
                count = 100; 
                status = 'hot';
            } else if (this.EXPERT_DATA_EURO.cold.includes(i)) {
                count = 10; 
                status = 'cold';
            } else {
                count += Math.floor(Math.random() * 20) - 10;
            }
        } else {
             // Fallback
             count += Math.floor(Math.random() * 20);
        }

        statsArray.push({
            number: i,
            count: count,
            frequency: count / 100, // normalized
            status: status
        });
    }

    statsArray.sort((a, b) => b.count - a.count);
    this.stats.set(statsArray.sort((a, b) => a.number - b.number));
  }

  private loadCustomImportStats() {
    const config = this.activeGameConfig();
    const statsArray: NumberStat[] = [];
    const counts = this.customDataCounts();
    const total = this.customDataTotalDraws();

    for (let i = 1; i <= config.totalNumbers; i++) {
        const count = counts[i] || 0;
        statsArray.push({
            number: i,
            count: count,
            frequency: total > 0 ? count / total : 0,
            status: 'neutral'
        });
    }

    statsArray.sort((a, b) => b.count - a.count);
    this.assignHotColdStatus(statsArray, config.totalNumbers);
    this.stats.set(statsArray.sort((a, b) => a.number - b.number));
  }

  private loadRealHistoryStats() {
    const config = this.activeGameConfig();
    const statsArray: NumberStat[] = [];
    const historicalData = this.REAL_DATA_2000_2024[this.activeGameId()] || {};
    const totalDrawsEstimate = 3500;

    for (let i = 1; i <= config.totalNumbers; i++) {
        let count = historicalData[i] || 100;
        count += Math.floor(Math.random() * 3); 

        statsArray.push({
            number: i,
            count: count,
            frequency: count / totalDrawsEstimate, 
            status: 'neutral'
        });
    }

    statsArray.sort((a, b) => b.count - a.count);
    this.assignHotColdStatus(statsArray, config.totalNumbers);
    this.stats.set(statsArray.sort((a, b) => a.number - b.number));
  }

  private applyManualStats() {
    const config = this.activeGameConfig();
    const statsArray: NumberStat[] = [];
    const manualHot = this.manualHotNumbers();

    for (let i = 1; i <= config.totalNumbers; i++) {
        let count = 0;
        if (manualHot.has(i)) {
            count = 100;
        } else {
            count = Math.floor(Math.random() * 50);
        }

        statsArray.push({
            number: i,
            count: count,
            frequency: count / 100,
            status: 'neutral'
        });
    }

    statsArray.sort((a, b) => b.count - a.count);

    const hotThreshold = Math.floor(config.totalNumbers * 0.2);
    const coldThreshold = Math.floor(config.totalNumbers * 0.8);

    statsArray.forEach((stat, index) => {
      if (manualHot.has(stat.number)) {
          stat.status = 'hot';
      } else {
        if (index < hotThreshold && !manualHot.has(stat.number)) stat.status = 'hot'; 
        else if (index > coldThreshold) stat.status = 'cold';
        else stat.status = 'neutral';
      }
    });

    this.stats.set(statsArray.sort((a, b) => a.number - b.number));
  }

  private runSimulation() {
    const config = this.activeGameConfig();
    const counts = new Map<number, number>();

    for (let i = 1; i <= config.totalNumbers; i++) {
      counts.set(i, 0);
    }

    for (let i = 0; i < this.HISTORY_SIZE; i++) {
      const draw = this.generateRandomDraw(config.totalNumbers, config.drawSize);
      draw.forEach(num => {
        counts.set(num, (counts.get(num) || 0) + 1);
      });
    }

    const statsArray: NumberStat[] = [];
    counts.forEach((count, num) => {
      statsArray.push({
        number: num,
        count: count,
        frequency: count / this.HISTORY_SIZE,
        status: 'neutral'
      });
    });

    statsArray.sort((a, b) => b.count - a.count);
    this.assignHotColdStatus(statsArray, config.totalNumbers);
    this.stats.set(statsArray.sort((a, b) => a.number - b.number));
  }

  private assignHotColdStatus(statsArray: NumberStat[], totalNumbers: number) {
    const hotThreshold = Math.floor(totalNumbers * 0.2);
    const coldThreshold = Math.floor(totalNumbers * 0.8);

    statsArray.forEach((stat, index) => {
      if (index < hotThreshold) stat.status = 'hot';
      else if (index > coldThreshold) stat.status = 'cold';
      else stat.status = 'neutral';
    });
  }

  generateSmartPrediction(): { numbers: number[], logic: string[] } {
    const config = this.activeGameConfig();
    const allStats = [...this.stats()].sort((a, b) => b.count - a.count);

    const selection = new Set<number>();
    const logic: string[] = [];

    // POOLS
    const hotPool = allStats.filter(s => s.status === 'hot');
    const coldPool = allStats.filter(s => s.status === 'cold');
    const neutralPool = allStats.filter(s => s.status === 'neutral');

    // Targets
    let hotTarget = Math.ceil(config.drawSize * 0.5); 
    const coldTarget = 1;

    // EXPERT MODE SPECIFIC LOGIC
    if (this.dataSource() === 'expert_trend') {
        if (this.activeGameId() === 'lotto') {
            logic.push(`Tryb Ekspert Lotto 2021-2025: Analiza trendów maszyn.`);
            const pairs = this.EXPERT_DATA_LOTTO.pairs;
            const randomPair = pairs[Math.floor(Math.random() * pairs.length)];

            if (Math.random() > 0.3) {
                randomPair.forEach(n => selection.add(n));
                logic.push(`Zastosowano regułę asocjacyjną: Para (${randomPair.join(' i ')}).`);
            }
            hotTarget = Math.max(0, hotTarget - selection.size);
        } else if (this.activeGameId() === 'mini') {
            logic.push(`Tryb Ekspert Mini 2021-2025: Analiza 5-letnia.`);
            const pairs = this.EXPERT_DATA_MINI.pairs;
            const randomPair = pairs[Math.floor(Math.random() * pairs.length)];

            // Higher pair probability for Mini as it's more frequent
            if (Math.random() > 0.25) {
                randomPair.forEach(n => selection.add(n));
                logic.push(`Silna korelacja par w Mini: (${randomPair.join(' i ')}).`);
            }
            hotTarget = Math.max(0, hotTarget - selection.size);
        } else if (this.activeGameId() === 'euro') {
            logic.push(`Tryb Ekspert Eurojackpot 2021-2025: Analiza europejska.`);
            const pairs = this.EXPERT_DATA_EURO.pairs;
            const randomPair = pairs[Math.floor(Math.random() * pairs.length)];

            if (Math.random() > 0.3) {
                randomPair.forEach(n => selection.add(n));
                logic.push(`Wykryto parę europejską: (${randomPair.join(' i ')}).`);
            }
            hotTarget = Math.max(0, hotTarget - selection.size);
        } else {
             logic.push(`Tryb Ekspert niedostępny dla tej gry, użyto danych statystycznych.`);
        }
    } 
    else if (this.dataSource() === 'manual') {
        logic.push(`Priorytet: Twoje zdefiniowane "Gorące Liczby".`);
    } else if (this.dataSource() === 'real_history') {
        logic.push(`Baza statystyczna 2000-2024: Wybrano liczby o najwyższym współczynniku wystąpień.`);
    } else if (this.dataSource() === 'custom_import') {
        logic.push(`Baza Własna (Import): Analiza ${this.customDataTotalDraws()} wklejonych losowań.`);
    } else {
        logic.push(`Wybrano liczby z grupy "Gorących" (trend wzrostowy).`);
    }

    // Pick Hot
    let attempts = 0;
    while (selection.size < (config.drawSize - coldTarget) && hotPool.length > 0 && attempts < 20) {
      const pick = this.pickRandomFrom(hotPool);
      if (!selection.has(pick.number)) selection.add(pick.number);
      attempts++;
    }

    // Pick Cold (unless we are full)
    attempts = 0;
    if (selection.size < config.drawSize) {
        while (selection.size < config.drawSize && coldPool.length > 0 && attempts < 5) {
        const pick = this.pickRandomFrom(coldPool);
        // In Expert mode, reduce chance of picking VERY cold numbers unless balancing
        if (!selection.has(pick.number)) {
             selection.add(pick.number);
             logic.push(`Dodano liczbę "Zimną" ${pick.number} (statystyczne wyrównanie).`);
             break; // usually just 1 cold is enough
        }
        attempts++;
        }
    }

    // Fill with Neutral or whatever is left
    attempts = 0;
    while (selection.size < config.drawSize && attempts < 100) {
      const pool = neutralPool.length > 0 ? neutralPool : allStats;
      const pick = this.pickRandomFrom(pool);
      if (!selection.has(pick.number)) selection.add(pick.number);
      attempts++;
    }

    if(selection.size === config.drawSize && !logic.some(l => l.includes('balansu'))) {
         logic.push(`Uzupełniono kupon dla balansu.`);
    }

    return {
      numbers: Array.from(selection).sort((a, b) => a - b),
      logic
    };
  }

  saveCoupon(numbers: number[], type: 'ai' | 'manual') {
    const newCoupon: Coupon = {
      id: crypto.randomUUID(),
      type: type,
      date: new Date(),
      gameId: this.activeGameId(),
      gameName: this.activeGameConfig().name,
      numbers: [...numbers].sort((a, b) => a - b),
      drawResult: null,
      matches: null,
      isRealCheck: false
    };
    this.savedCoupons.update(prev => [newCoupon, ...prev]);
  }

  checkCouponResult(couponId: string) {
    const config = this.activeGameConfig();
    const draw = this.generateRandomDraw(config.totalNumbers, config.drawSize).sort((a, b) => a - b);

    this.savedCoupons.update(coupons => coupons.map(c => {
      if (c.id === couponId) {
        const matches = c.numbers.filter(n => draw.includes(n)).length;
        return { ...c, drawResult: draw, matches, isRealCheck: false };
      }
      return c;
    }));
  }

  checkCouponsAgainstRealNumbers(winningNumbers: number[]) {
    const sortedWinning = [...winningNumbers].sort((a, b) => a - b);
    const currentGameId = this.activeGameId();

    this.savedCoupons.update(coupons => coupons.map(c => {
      if (c.gameId === currentGameId) {
        const matches = c.numbers.filter(n => sortedWinning.includes(n)).length;
        return { 
          ...c, 
          drawResult: sortedWinning, 
          matches,
          isRealCheck: true 
        };
      }
      return c;
    }));
  }

  clearHistory() {
    this.savedCoupons.set([]);
  }

  private pickRandomFrom(pool: NumberStat[]): NumberStat {
    if (pool.length === 0) return this.stats()[Math.floor(Math.random() * this.stats().length)];
    const idx = Math.floor(Math.random() * pool.length);
    return pool[idx];
  }

  private generateRandomDraw(total: number, size: number): number[] {
    const numbers = new Set<number>();
    while (numbers.size < size) {
      numbers.add(Math.floor(Math.random() * total) + 1);
    }
    return Array.from(numbers);
  }
}

