        setTimeout(() => this.importSuccess.set(false), 3000);
        this.currentView.set('analyze');
    } else {
        alert('Nie udało się zaimportować danych. Sprawdź format.');
    }
  }

  private resetState() {
    this.prediction.set([]);
    this.predictionBonus.set([]);
    this.logicSteps.set([]);
    this.aiExplanation.set('');
    this.manualNumbers.set(new Set());
    this.manualBonusNumbers.set(new Set());
    this.isManualMode.set(false);
  }

  async generatePrediction() {
    this.loading.set(true);
    this.prediction.set([]); 
    this.predictionBonus.set([]);
    this.aiExplanation.set('');
    this.logicSteps.set([]);
    this.isManualMode.set(false);

    await new Promise(resolve => setTimeout(resolve, 600));

    const result = this.lottoService.generateSmartPrediction();

    this.prediction.set(result.numbers);
    this.predictionBonus.set(result.bonusNumbers);
    this.logicSteps.set(result.logic);
    this.loading.set(false);

    let contextString = result.numbers.join(', ');
    if (result.bonusNumbers.length > 0) {
        contextString += ` + (Bonus: ${result.bonusNumbers.join(', ')})`;
    }

    const explanation = await this.geminiService.explainPrediction(
      result.numbers, 
      this.lottoService.stats(),
      this.lottoService.activeGameConfig().name
    );

    this.aiExplanation.set(explanation);
  }

  saveCurrentPrediction() {
    if (this.prediction().length > 0) {
      this.lottoService.saveCoupon(this.prediction(), this.predictionBonus(), 'ai');
      this.currentView.set('history');
    }
  }

  clearHistory() {
    if (confirm('Czy na pewno chcesz usunąć całą historię kuponów?')) {
      this.lottoService.clearHistory();
    }
  }

  shareApp() {
    const url = window.location.href;
    const shareData = {
      title: 'Lotto Data Scientist',
      text: 'Sprawdź swoje szanse w Lotto z analizą AI!',
      url: url
    };
    if (navigator.share) {
      navigator.share(shareData).catch((err) => console.log('Error sharing:', err));
    } else {
      navigator.clipboard.writeText(url).then(() => {
        this.linkCopied.set(true);
        setTimeout(() => this.linkCopied.set(false), 2000);
      });
    }
  }
}

import { Injectable, signal, computed, effect } from '@angular/core';

export type GameType = 'lotto' | 'mini' | 'euro';
// Removed 'simulation' and 'real_history' to focus on the 5-year expert system
export type DataSource = 'manual' | 'custom_import' | 'expert_trend';

export interface GameConfig {
  id: GameType;
  name: string;
  totalNumbers: number;
  drawSize: number;
  // Optional configuration for bonus numbers (Eurojackpot)
  bonusTotalNumbers?: number;
  bonusDrawSize?: number;
  color: string;
}

export interface NumberStat {
  number: number;
  count: number;
  frequency: number; // percentage
  status: 'hot' | 'neutral' | 'cold';
}

export interface Coupon {
  id: string;
  type: 'ai' | 'manual';
  date: Date;
  gameId: GameType;
  gameName: string;
  numbers: number[];       // Main numbers
  bonusNumbers: number[];  // Euro numbers
  drawResult: number[] | null; // Main draw
  bonusDrawResult: number[] | null; // Bonus draw
  matches: number | null;
  bonusMatches: number | null;
  isRealCheck?: boolean;
}

@Injectable({
  providedIn: 'root'
})
export class LottoStatsService {

  readonly games: GameConfig[] = [
    { id: 'lotto', name: 'Lotto', totalNumbers: 49, drawSize: 6, color: 'text-yellow-500' },
    { id: 'mini', name: 'Mini Lotto', totalNumbers: 42, drawSize: 5, color: 'text-blue-400' },
    { 
      id: 'euro', 
      name: 'Eurojackpot', 
      totalNumbers: 50, 
      drawSize: 5, 
      bonusTotalNumbers: 12, 
      bonusDrawSize: 2, 
      color: 'text-orange-500' 
    }
  ];

  /**
   * EXPERT KNOWLEDGE BASE (2021-2025 Trends)
   * Specific to Polish Lotto (1-49).
   */
  private readonly EXPERT_DATA_LOTTO = {
    hot: [4, 30, 14, 2, 44, 24],
    cold: [43, 48, 33, 1],
    pairs: [[4, 30], [17, 21], [24, 29], [15, 25]]
  };

  /**
   * EXPERT KNOWLEDGE BASE (2021-2025 Trends)
   * Specific to Mini Lotto (1-42).
   */
  private readonly EXPERT_DATA_MINI = {
    hot: [21, 28, 4, 36, 30, 6],
    cold: [14, 20, 25],
    pairs: [[21, 30], [6, 28], [28, 36]]
  };

  /**
   * EXPERT KNOWLEDGE BASE (2021-2026 Trends)
   * Specific to Eurojackpot (5/50 + 2/12).
   */
  private readonly EXPERT_DATA_EURO = {
    // Main Numbers (1-50)
    hotMain: [34, 49, 20, 7, 35],
    coldMain: [48, 2, 5, 23],

    // Euro Numbers (1-12)
    hotBonus: [3, 8, 5], 
    // 11 and 12 are statistically colder due to being added only in 2022

    pairs: [[34, 49], [7, 35]]
  };

  // State
  activeGameId = signal<GameType>('lotto');

  // DEFAULT IS NOW EXPERT TREND
  dataSource = signal<DataSource>('expert_trend');

  manualHotNumbers = signal<Set<number>>(new Set());

  // Custom Data State
  customDataCounts = signal<Record<number, number>>({});
  customDataPairs = signal<number[][]>([]); // NEW: Store correlations from import
  customDataTotalDraws = signal<number>(0);

  stats = signal<NumberStat[]>([]);

  savedCoupons = signal<Coupon[]>([]);

  activeGameConfig = computed(() => 
    this.games.find(g => g.id === this.activeGameId())!
  );

  // Computed for correlation/pairs display
  topPairs = computed(() => {
    if (this.dataSource() === 'expert_trend') {
       if (this.activeGameId() === 'lotto') return this.EXPERT_DATA_LOTTO.pairs;
       if (this.activeGameId() === 'mini') return this.EXPERT_DATA_MINI.pairs;
       if (this.activeGameId() === 'euro') return this.EXPERT_DATA_EURO.pairs;
    }
    if (this.dataSource() === 'custom_import') {
        return this.customDataPairs();
    }
    return [];
  });

  constructor() {
    effect(() => {
        this.calculateStats();
    });
  }

  setGame(gameId: GameType) {
    this.activeGameId.set(gameId);
    this.manualHotNumbers.set(new Set()); 
  }

  setDataSource(source: DataSource) {
    this.dataSource.set(source);
  }

  toggleManualHotNumber(num: number) {
    const current = new Set(this.manualHotNumbers());
    if (current.has(num)) {
      current.delete(num);
    } else {
      current.add(num);
    }
    this.manualHotNumbers.set(current);
  }

  // PARSER for User Data
  processImportedData(text: string): boolean {
    const counts: Record<number, number> = {};
    const pairCounts: Record<string, number> = {};
    let validDraws = 0;
    const lines = text.split('\n');

    const regex = /(\d{1,2}[,.\s]\d{1,2}[,.\s]\d{1,2}[,.\s]\d{1,2}[,.\s]\d{1,2})/; 

    for (const line of lines) {
        const match = line.match(regex);
        if (match) {
            const numbersPart = match[0];
            const nums = numbersPart.split(/[,.\s]+/).map(n => parseInt(n.trim()));
            const config = this.activeGameConfig();
            const validNums = nums.filter(n => !isNaN(n) && n >= 1 && n <= config.totalNumbers);
            const sortedNums = [...validNums].sort((a, b) => a - b);

            if (validNums.length >= 5) { 
                validDraws++;
                // Count individual numbers
                validNums.forEach(n => {
                    counts[n] = (counts[n] || 0) + 1;
                });

                // Calculate Pairs (Correlations)
                for (let i = 0; i < sortedNums.length; i++) {
                    for (let j = i + 1; j < sortedNums.length; j++) {
                        const key = `${sortedNums[i]}-${sortedNums[j]}`;
                        pairCounts[key] = (pairCounts[key] || 0) + 1;
                    }
                }
            }
        }
    }

    if (validDraws > 0) {
        this.customDataCounts.set(counts);
        this.customDataTotalDraws.set(validDraws);

        // Process top pairs from import
        const sortedPairs = Object.entries(pairCounts)
            .sort(([, countA], [, countB]) => countB - countA)
            .slice(0, 4)
            .map(([key]) => key.split('-').map(Number));

        this.customDataPairs.set(sortedPairs);

        this.setDataSource('custom_import');
        return true;
    }
    return false;
  }

  private calculateStats() {
    switch (this.dataSource()) {
      case 'expert_trend':
        this.loadExpertTrendStats();
        break;
      case 'manual':
        this.applyManualStats();
        break;
      case 'custom_import':
        this.loadCustomImportStats();
        break;
      // Default fallback to expert if something goes wrong
      default:
        this.loadExpertTrendStats();
        break;
    }
  }

  private loadExpertTrendStats() {
    const config = this.activeGameConfig();
    const statsArray: NumberStat[] = [];

    const baseCount = 50;

    for (let i = 1; i <= config.totalNumbers; i++) {
        let count = baseCount;
        let status: 'hot' | 'neutral' | 'cold' = 'neutral';

        if (this.activeGameId() === 'lotto') {
            if (this.EXPERT_DATA_LOTTO.hot.includes(i)) { count = 100; status = 'hot'; }
            else if (this.EXPERT_DATA_LOTTO.cold.includes(i)) { count = 10; status = 'cold'; }
        } else if (this.activeGameId() === 'mini') {
            if (this.EXPERT_DATA_MINI.hot.includes(i)) { count = 100; status = 'hot'; }
            else if (this.EXPERT_DATA_MINI.cold.includes(i)) { count = 10; status = 'cold'; }
        } else if (this.activeGameId() === 'euro') {
             if (this.EXPERT_DATA_EURO.hotMain.includes(i)) { count = 100; status = 'hot'; }
             else if (this.EXPERT_DATA_EURO.coldMain.includes(i)) { count = 10; status = 'cold'; }
        }

        // Add noise to make charts look alive but keeping the trend
        if (status === 'neutral') count += Math.floor(Math.random() * 20) - 10;

        statsArray.push({
            number: i,
            count: count,
            frequency: count / 100,
            status: status
        });
    }

    statsArray.sort((a, b) => b.count - a.count);
    this.stats.set(statsArray.sort((a, b) => a.number - b.number));
  }

  private loadCustomImportStats() {
    const config = this.activeGameConfig();
    const statsArray: NumberStat[] = [];
    const counts = this.customDataCounts();
    const total = this.customDataTotalDraws();

    for (let i = 1; i <= config.totalNumbers; i++) {
        const count = counts[i] || 0;
        statsArray.push({
            number: i,
            count: count,
            frequency: total > 0 ? count / total : 0,
            status: 'neutral'
        });
    }
    statsArray.sort((a, b) => b.count - a.count);
    this.assignHotColdStatus(statsArray, config.totalNumbers);
    this.stats.set(statsArray.sort((a, b) => a.number - b.number));
  }

  private applyManualStats() {
    const config = this.activeGameConfig();
    const statsArray: NumberStat[] = [];
    const manualHot = this.manualHotNumbers();

    for (let i = 1; i <= config.totalNumbers; i++) {
        statsArray.push({
            number: i,
            count: manualHot.has(i) ? 100 : Math.floor(Math.random() * 50),
            frequency: 0,
            status: manualHot.has(i) ? 'hot' : 'neutral'
        });
    }
    statsArray.sort((a, b) => b.count - a.count);
    this.assignHotColdStatus(statsArray, config.totalNumbers, manualHot);
    this.stats.set(statsArray.sort((a, b) => a.number - b.number));
  }

  private assignHotColdStatus(statsArray: NumberStat[], totalNumbers: number, manualHot?: Set<number>) {
    const hotThreshold = Math.floor(totalNumbers * 0.2);
    const coldThreshold = Math.floor(totalNumbers * 0.8);

    statsArray.forEach((stat, index) => {
      if (manualHot && manualHot.has(stat.number)) {
          stat.status = 'hot';
      } else {
        if (index < hotThreshold && (!manualHot || !manualHot.has(stat.number))) stat.status = 'hot';
        else if (index > coldThreshold) stat.status = 'cold';
        else stat.status = 'neutral';
      }
    });
  }

  generateSmartPrediction(): { numbers: number[], bonusNumbers: number[], logic: string[] } {
    const config = this.activeGameConfig();
    const allStats = [...this.stats()].sort((a, b) => b.count - a.count);

    const selection = new Set<number>();
    const bonusSelection = new Set<number>();
    const logic: string[] = [];

    // 1. MAIN NUMBERS LOGIC
    const hotPool = allStats.filter(s => s.status === 'hot');
    const coldPool = allStats.filter(s => s.status === 'cold');
    const neutralPool = allStats.filter(s => s.status === 'neutral');

    let hotTarget = Math.ceil(config.drawSize * 0.5);

    // Logic is primarily EXPERT now
    if (this.dataSource() === 'expert_trend') {
        if (this.activeGameId() === 'lotto') {
            logic.push(`Lotto Expert: Analiza 2021-2025.`);
            this.tryAddPair(selection, this.EXPERT_DATA_LOTTO.pairs, logic);
        } else if (this.activeGameId() === 'mini') {
            logic.push(`Mini Expert: 5-letni trend.`);
            this.tryAddPair(selection, this.EXPERT_DATA_MINI.pairs, logic);
        } else if (this.activeGameId() === 'euro') {
            logic.push(`Eurojackpot Expert: Trend (34, 49, 20...).`);
            this.tryAddPair(selection, this.EXPERT_DATA_EURO.pairs, logic);
        }
        hotTarget = Math.max(0, hotTarget - selection.size);
    } else {
         logic.push(`Strategia użytkownika (Import/Manual).`);
         // Use correlations from import if available
         if (this.dataSource() === 'custom_import' && this.customDataPairs().length > 0) {
            this.tryAddPair(selection, this.customDataPairs(), logic);
         }
    }

    // Fill Main
    this.fillFromPool(selection, hotPool, config.drawSize - 1); // Heavily favor hot
    this.fillFromPool(selection, coldPool, config.drawSize); // Add maybe 1 cold
    this.fillFromPool(selection, neutralPool, config.drawSize); // Fill rest
    // Final check
    while (selection.size < config.drawSize) {
        const r = Math.floor(Math.random() * config.totalNumbers) + 1;
        selection.add(r);
    }

    // 2. BONUS NUMBERS LOGIC (Only for Euro)
    if (config.bonusTotalNumbers && config.bonusDrawSize) {
        if (this.dataSource() === 'expert_trend' && this.activeGameId() === 'euro') {
            logic.push(`Euro Bonus: Priorytet (3, 8, 5) - "Królowie Bonusów".`);

            // Try adding hot bonus numbers
            const hotBonus = this.EXPERT_DATA_EURO.hotBonus;
            // 70% chance to pick at least one hot bonus
            if (Math.random() < 0.7) {
                const pick = hotBonus[Math.floor(Math.random() * hotBonus.length)];
                bonusSelection.add(pick);
            }
        }

        // Fill rest of bonus
        let safeCounter = 0;
        while (bonusSelection.size < config.bonusDrawSize && safeCounter < 100) {
            safeCounter++;
            const r = Math.floor(Math.random() * config.bonusTotalNumbers) + 1;

            // EXPERT LOGIC:
            // Penalize 11 and 12 in Eurojackpot Expert Mode because they were added in 2022
            if (this.dataSource() === 'expert_trend' && this.activeGameId() === 'euro') {
                if ((r === 11 || r === 12) && Math.random() > 0.15) {
                    continue; 
                }
            }
            bonusSelection.add(r);
        }
    }

    return {
      numbers: Array.from(selection).sort((a, b) => a - b),
      bonusNumbers: Array.from(bonusSelection).sort((a, b) => a - b),
      logic
    };
  }

  private tryAddPair(selection: Set<number>, pairs: number[][], logic: string[]) {
      if (Math.random() > 0.3 && pairs.length > 0) {
        const pair = pairs[Math.floor(Math.random() * pairs.length)];
        // Only add if not already present
        if (!pair.some(p => selection.has(p))) {
            pair.forEach(n => selection.add(n));
            logic.push(`Wykryto silną parę: (${pair.join(' i ')}).`);
        }
      }
  }

  private fillFromPool(selection: Set<number>, pool: NumberStat[], targetSize: number) {
      if (selection.size >= targetSize) return;
      const shuffled = [...pool].sort(() => 0.5 - Math.random());

      for (const stat of shuffled) {
          if (selection.size >= targetSize) break;
          selection.add(stat.number);
      }
  }

  saveCoupon(numbers: number[], bonusNumbers: number[], type: 'ai' | 'manual') {
    const newCoupon: Coupon = {
      id: crypto.randomUUID(),
      type: type,
      date: new Date(),
      gameId: this.activeGameId(),
      gameName: this.activeGameConfig().name,
      numbers: [...numbers].sort((a, b) => a - b),
      bonusNumbers: [...bonusNumbers].sort((a, b) => a - b),
      drawResult: null,
      bonusDrawResult: null,
      matches: null,
      bonusMatches: null,
      isRealCheck: false
    };
    this.savedCoupons.update(prev => [newCoupon, ...prev]);
  }

  checkCouponResult(couponId: string) {
    const config = this.activeGameConfig();
    const draw = this.generateRandomDraw(config.totalNumbers, config.drawSize).sort((a, b) => a - b);
    let bonusDraw: number[] = [];
    if (config.bonusTotalNumbers && config.bonusDrawSize) {
        bonusDraw = this.generateRandomDraw(config.bonusTotalNumbers, config.bonusDrawSize).sort((a, b) => a - b);
    }

    this.savedCoupons.update(coupons => coupons.map(c => {
      if (c.id === couponId) {
        const matches = c.numbers.filter(n => draw.includes(n)).length;
        const bonusMatches = c.bonusNumbers.filter(n => bonusDraw.includes(n)).length;
        return { 
            ...c, 
            drawResult: draw, 
            bonusDrawResult: bonusDraw, 
            matches, 
            bonusMatches,
            isRealCheck: false 
        };
      }
      return c;
    }));
  }

  checkCouponsAgainstRealNumbers(winningNumbers: number[], bonusWinningNumbers: number[] = []) {
    const sortedWinning = [...winningNumbers].sort((a, b) => a - b);
    const sortedBonus = [...bonusWinningNumbers].sort((a, b) => a - b);
    const currentGameId = this.activeGameId();

    this.savedCoupons.update(coupons => coupons.map(c => {
      if (c.gameId === currentGameId) {
        const matches = c.numbers.filter(n => sortedWinning.includes(n)).length;
        const bonusMatches = c.bonusNumbers.filter(n => sortedBonus.includes(n)).length;
        return { 
          ...c, 
          drawResult: sortedWinning, 
          bonusDrawResult: sortedBonus,
          matches,
          bonusMatches,
          isRealCheck: true 
        };
      }
      return c;
    }));
  }

  clearHistory() {
    this.savedCoupons.set([]);
  }

  private pickRandomFrom(pool: NumberStat[]): NumberStat {
    if (pool.length === 0) return this.stats()[Math.floor(Math.random() * this.stats().length)];
    const idx = Math.floor(Math.random() * pool.length);
    return pool[idx];
  }

  private generateRandomDraw(total: number, size: number): number[] {
    const numbers = new Set<number>();
    while (numbers.size < size) {
      numbers.add(Math.floor(Math.random() * total) + 1);
    }
    return Array.from(numbers);
  }
}

import { Component, input, computed } from '@angular/core';
import { NumberStat } from '../services/lotto-stats.service';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-histogram',
  standalone: true,
  imports: [CommonModule],
  template: `
    <div class="w-full">
      @if (mode() === 'bars') {
        <div class="overflow-x-auto pb-2">
          <div class="h-40 min-w-[300px] flex items-end justify-between gap-[1px] bg-slate-800/50 p-2 rounded-lg border border-slate-700">
            @for (stat of sortedStats(); track stat.number) {
              <div 
                class="relative flex-1 rounded-t-sm transition-all duration-500 hover:bg-white group"
                [style.height.%]="(stat.count / maxCount()) * 100"
                [class.bg-red-500]="stat.status === 'hot'"
                [class.bg-blue-500]="stat.status === 'cold'"
                [class.bg-slate-400]="stat.status === 'neutral'"
                [class.opacity-100]="isHighlighted(stat.number)"
                [class.opacity-30]="highlightNumbers().length > 0 && !isHighlighted(stat.number)"
              >
                <!-- Tooltip -->
                <div class="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 hidden group-hover:block z-10 w-max pointer-events-none">
                  <div class="bg-black text-[10px] text-white px-2 py-1 rounded border border-slate-600 shadow-xl">
                    #{{ stat.number }} ({{ stat.count }})
                  </div>
                </div>
              </div>
            }
          </div>
        </div>
      } @else {
        <!-- HEATMAP MODE -->
        <div class="grid grid-cols-7 gap-1.5 animate-[fadeIn_0.3s]">
          @for (stat of sortedStats(); track stat.number) {
             <div 
                class="aspect-square flex flex-col items-center justify-center rounded text-xs font-bold border transition-all duration-300 relative overflow-hidden"
                [style.background-color]="getHeatmapColor(stat.count)"
                [class.border-transparent]="!isHighlighted(stat.number)"
                [class.border-white]="isHighlighted(stat.number)"
                [class.scale-110]="isHighlighted(stat.number)"
                [class.z-10]="isHighlighted(stat.number)"
                [class.shadow-lg]="isHighlighted(stat.number)"
             >
                <span class="text-white/90 drop-shadow-md z-10">{{ stat.number }}</span>
                @if(stat.status === 'hot') { <div class="absolute top-0 right-0 w-1.5 h-1.5 bg-white rounded-full m-0.5"></div> }
             </div>
          }
        </div>
      }

      <div class="flex flex-wrap gap-4 justify-center mt-3 text-[10px] text-slate-400">
        <div class="flex items-center gap-1"><span class="w-2 h-2 bg-red-500 rounded-sm"></span> Hot</div>
        <div class="flex items-center gap-1"><span class="w-2 h-2 bg-slate-400 rounded-sm"></span> Neutral</div>
        <div class="flex items-center gap-1"><span class="w-2 h-2 bg-blue-500 rounded-sm"></span> Cold</div>
      </div>
    </div>
  `
})
export class HistogramComponent {
  data = input.required<NumberStat[]>();
  highlightNumbers = input<number[]>([]);
  mode = input<'bars' | 'heatmap'>('bars');

  sortedStats = computed(() => {
    return [...this.data()].sort((a, b) => a.number - b.number);
  });

  maxCount = computed(() => {
    return Math.max(...this.data().map(s => s.count), 1);
  });

  isHighlighted(num: number): boolean {
    return this.highlightNumbers().includes(num);
  }

  getHeatmapColor(count: number): string {
      const max = this.maxCount();
      const intensity = count / max;

      // Interpolate between Blue (Cold) -> Slate (Neutral) -> Red (Hot)
      // Simplified approach using tailwind-like logic via inline styles or just hardcoded HSL
      if (intensity > 0.7) {
          // Hotter (Red)
          const alpha = 0.5 + (intensity - 0.7) * 1.6; // 0.5 to 1.0
          return `rgba(239, 68, 68, ${Math.min(alpha, 1)})`; // red-500
      } else if (intensity < 0.3) {
           // Colder (Blue)
           const alpha = 0.5 + (0.3 - intensity) * 1.6;
           return `rgba(59, 130, 246, ${Math.min(alpha, 1)})`; // blue-500
      } else {
           // Neutral (Slate)
           return `rgba(100, 116, 139, 0.5)`; // slate-500 with opacity
      }
  }
}

import { Component, signal, inject, computed, effect } from '@angular/core';
import { CommonModule, DOCUMENT } from '@angular/common';
import { LottoStatsService, GameType } from './services/lotto-stats.service';
import { GeminiService } from './services/gemini.service';
import { HistogramComponent } from './components/histogram.component';

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [CommonModule, HistogramComponent],
  templateUrl: './app.component.html'
})
export class AppComponent {
  lottoService = inject(LottoStatsService);
  geminiService = inject(GeminiService);

  // UI State
  currentView = signal<'analyze' | 'history' | 'settings'>('analyze');
  isManualMode = signal(false);
  visualizationMode = signal<'bars' | 'heatmap'>('bars');

  // Theme & Fullscreen State
  isDarkMode = signal(true);
  isFullscreen = signal(false);

  // History Filter State
  historyFilter = signal<'all' | GameType>('all');

  // Real Check Mode State (in History)
  isCheckMode = signal(false);
  winningNumbersSelection = signal<Set<number>>(new Set());
  winningBonusSelection = signal<Set<number>>(new Set());

  // Import Data State
  importText = signal('');
  importSuccess = signal(false);

  // AI Logic State
  loading = signal(false);
  prediction = signal<number[]>([]);
  predictionBonus = signal<number[]>([]);
  logicSteps = signal<string[]>([]);
  aiExplanation = signal<string>('');

  // Manual Entry State
  manualNumbers = signal<Set<number>>(new Set());
  manualBonusNumbers = signal<Set<number>>(new Set());

  // Feedback state
  linkCopied = signal(false);

  constructor() {
    // Effect to handle Dark Mode class on HTML element
    effect(() => {
      const html = document.documentElement;
      if (this.isDarkMode()) {
        html.classList.add('dark');
      } else {
        html.classList.remove('dark');
      }
    });

    // Listen to fullscreen changes to update state if user uses ESC key
    document.addEventListener('fullscreenchange', () => {
      this.isFullscreen.set(!!document.fullscreenElement);
    });
  }

  // Computed helper for MAIN grid generation
  gridNumbers = computed(() => {
    return Array.from({ length: this.lottoService.activeGameConfig().totalNumbers }, (_, i) => i + 1);
  });

  // Computed helper for BONUS grid generation (Eurojackpot)
  bonusGridNumbers = computed(() => {
    const max = this.lottoService.activeGameConfig().bonusTotalNumbers || 0;
    return Array.from({ length: max }, (_, i) => i + 1);
  });

  isManualComplete = computed(() => {
    const config = this.lottoService.activeGameConfig();
    const mainOk = this.manualNumbers().size === config.drawSize;
    const bonusOk = config.bonusDrawSize ? this.manualBonusNumbers().size === config.bonusDrawSize : true;
    return mainOk && bonusOk;
  });

  // For Checking Mode
  isWinningSelectionComplete = computed(() => {
    const config = this.lottoService.activeGameConfig();
    const mainOk = this.winningNumbersSelection().size === config.drawSize;
    const bonusOk = config.bonusDrawSize ? this.winningBonusSelection().size === config.bonusDrawSize : true;
    return mainOk && bonusOk;
  });

  // Filtered Coupons for History View
  filteredCoupons = computed(() => {
    const all = this.lottoService.savedCoupons();
    const filter = this.historyFilter();
    if (filter === 'all') return all;
    return all.filter(c => c.gameId === filter);
  });

  // Dashboard Stats Helpers
  topHotNumbers = computed(() => {
    return [...this.lottoService.stats()]
      .filter(s => s.status === 'hot')
      .sort((a, b) => b.count - a.count)
      .slice(0, 5);
  });

  topColdNumbers = computed(() => {
    return [...this.lottoService.stats()]
      .filter(s => s.status === 'cold')
      .sort((a, b) => a.count - b.count) // asc count
      .slice(0, 5);
  });

  oddEvenRatio = computed(() => {
    const hot = this.topHotNumbers();
    if (hot.length === 0) return '50/50';
    const odd = hot.filter(n => n.number % 2 !== 0).length;
    const even = hot.length - odd;
    return `${odd} (NP) / ${even} (P)`;
  });

  toggleTheme() {
    this.isDarkMode.update(v => !v);
  }

  toggleFullscreen() {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(err => {
        console.error(`Error attempting to enable fullscreen: ${err.message}`);
      });
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
      }
    }
  }

  toggleVisualizationMode(mode: 'bars' | 'heatmap') {
      this.visualizationMode.set(mode);
  }

  switchGame(gameId: GameType) {
    this.lottoService.setGame(gameId);
    this.resetState();
    this.isCheckMode.set(false);
    this.winningNumbersSelection.set(new Set());
    this.winningBonusSelection.set(new Set());
  }

  toggleManualMode() {
    this.isManualMode.update(v => !v);
    this.manualNumbers.set(new Set());
    this.manualBonusNumbers.set(new Set());
  }

  // Toggle for the Real Check Mode in History
  toggleCheckMode() {
    this.isCheckMode.update(v => !v);
    this.winningNumbersSelection.set(new Set());
    this.winningBonusSelection.set(new Set());
  }

  setHistoryFilter(filter: 'all' | GameType) {
    this.historyFilter.set(filter);
  }

  toggleManualNumber(num: number) {
    const current = new Set(this.manualNumbers());
    const limit = this.lottoService.activeGameConfig().drawSize;
    if (current.has(num)) current.delete(num);
    else if (current.size < limit) current.add(num);
    this.manualNumbers.set(current);
  }

  toggleManualBonusNumber(num: number) {
    const current = new Set(this.manualBonusNumbers());
    const limit = this.lottoService.activeGameConfig().bonusDrawSize || 0;
    if (current.has(num)) current.delete(num);
    else if (current.size < limit) current.add(num);
    this.manualBonusNumbers.set(current);
  }

  toggleWinningNumber(num: number) {
    const current = new Set(this.winningNumbersSelection());
    const limit = this.lottoService.activeGameConfig().drawSize;
    if (current.has(num)) current.delete(num);
    else if (current.size < limit) current.add(num);
    this.winningNumbersSelection.set(current);
  }

  toggleWinningBonusNumber(num: number) {
    const current = new Set(this.winningBonusSelection());
    const limit = this.lottoService.activeGameConfig().bonusDrawSize || 0;
    if (current.has(num)) current.delete(num);
    else if (current.size < limit) current.add(num);
    this.winningBonusSelection.set(current);
  }

  saveManualCoupon() {
    if (this.isManualComplete()) {
      this.lottoService.saveCoupon(
          Array.from(this.manualNumbers()), 
          Array.from(this.manualBonusNumbers()),
          'manual'
      );
      this.currentView.set('history');
      this.isManualMode.set(false);
      this.manualNumbers.set(new Set());
      this.manualBonusNumbers.set(new Set());
    }
  }

  confirmRealCheck() {
    if (this.isWinningSelectionComplete()) {
      this.lottoService.checkCouponsAgainstRealNumbers(
          Array.from(this.winningNumbersSelection()),
          Array.from(this.winningBonusSelection())
      );
      this.isCheckMode.set(false);
      this.winningNumbersSelection.set(new Set());
      this.winningBonusSelection.set(new Set());
    }
  }

  onPasteResults(event: ClipboardEvent) {
    const clipboardData = event.clipboardData;
    const pastedText = clipboardData?.getData('text') || '';

    // Parse numbers
    const numbers = pastedText.split(/[\s,]+/)
      .map(s => parseInt(s.trim()))
      .filter(n => !isNaN(n));

    const config = this.lottoService.activeGameConfig();
    const newMain = new Set<number>();
    const newBonus = new Set<number>();

    // Simple logic: Fill Main first, then Bonus if Eurojackpot
    let i = 0;
    // Fill Main
    while(newMain.size < config.drawSize && i < numbers.length) {
        const n = numbers[i++];
        if (n >= 1 && n <= config.totalNumbers) newMain.add(n);
    }

    // Fill Bonus (if applicable)
    if (config.bonusTotalNumbers) {
        while(newBonus.size < (config.bonusDrawSize || 0) && i < numbers.length) {
            const n = numbers[i++];
             if (n >= 1 && n <= config.bonusTotalNumbers) newBonus.add(n);
        }
    }

    if (newMain.size > 0) this.winningNumbersSelection.set(newMain);
    if (newBonus.size > 0) this.winningBonusSelection.set(newBonus);
  }

  onImportTextChange(event: Event) {
    const target = event.target as HTMLTextAreaElement;
    this.importText.set(target.value);
  }

  processImport() {
    const success = this.lottoService.processImportedData(this.importText());
    if (success) {
        this.importSuccess.set(true);
        this.importText.set('');
        setTimeout(() => this.importSuccess.set(false), 3000);
        this.currentView.set('analyze');
    } else {
        alert('Nie udało się zaimportować danych. Sprawdź format.');
    }
  }

  private resetState() {
    this.prediction.set([]);
    this.predictionBonus.set([]);
    this.logicSteps.set([]);
    this.aiExplanation.set('');
    this.manualNumbers.set(new Set());
    this.manualBonusNumbers.set(new Set());
    this.isManualMode.set(false);
  }

  async generatePrediction() {
    this.loading.set(true);
    this.prediction.set([]); 
    this.predictionBonus.set([]);
    this.aiExplanation.set('');
    this.logicSteps.set([]);
    this.isManualMode.set(false);

    await new Promise(resolve => setTimeout(resolve, 600));

    const result = this.lottoService.generateSmartPrediction();

    this.prediction.set(result.numbers);
    this.predictionBonus.set(result.bonusNumbers);
    this.logicSteps.set(result.logic);
    this.loading.set(false);

    let contextString = result.numbers.join(', ');
    if (result.bonusNumbers.length > 0) {
        contextString += ` + (Bonus: ${result.bonusNumbers.join(', ')})`;
    }

    const explanation = await this.geminiService.explainPrediction(
      result.numbers, 
      this.lottoService.stats(),
      this.lottoService.activeGameConfig().name
    );

    this.aiExplanation.set(explanation);
  }

  saveCurrentPrediction() {
    if (this.prediction().length > 0) {
      this.lottoService.saveCoupon(this.prediction(), this.predictionBonus(), 'ai');
      this.currentView.set('history');
    }
  }

  clearHistory() {
    if (confirm('Czy na pewno chcesz usunąć całą historię kuponów?')) {
      this.lottoService.clearHistory();
    }
  }

  shareApp() {
    const url = window.location.href;
    const shareData = {
      title: 'Lotto Data Scientist',
      text: 'Sprawdź swoje szanse w Lotto z analizą AI!',
      url: url
    };
    if (navigator.share) {
      navigator.share(shareData).catch((err) => console.log('Error sharing:', err));
    } else {
      navigator.clipboard.writeText(url).then(() => {
        this.linkCopied.set(true);
        setTimeout(() => this.linkCopied.set(false), 2000);
      });
    }
  }
}

import { Injectable, signal, computed, effect } from '@angular/core';

export type GameType = 'lotto' | 'mini' | 'euro';
// Removed 'simulation' and 'real_history' to focus on the 5-year expert system
export type DataSource = 'manual' | 'custom_import' | 'expert_trend';

export interface GameConfig {
  id: GameType;
  name: string;
  totalNumbers: number;
  drawSize: number;
  // Optional configuration for bonus numbers (Eurojackpot)
  bonusTotalNumbers?: number;
  bonusDrawSize?: number;
  color: string;
}

export interface NumberStat {
  number: number;
  count: number;
  frequency: number; // percentage
  status: 'hot' | 'neutral' | 'cold';
}

export interface Coupon {
  id: string;
  type: 'ai' | 'manual';
  date: Date;
  gameId: GameType;
  gameName: string;
  numbers: number[];       // Main numbers
  bonusNumbers: number[];  // Euro numbers
  drawResult: number[] | null; // Main draw
  bonusDrawResult: number[] | null; // Bonus draw
  matches: number | null;
  bonusMatches: number | null;
  isRealCheck?: boolean;
}

export interface PastDraw {
  date: string;
  numbers: number[];
  bonusNumbers: number[];
}

@Injectable({
  providedIn: 'root'
})
export class LottoStatsService {

  readonly games: GameConfig[] = [
    { id: 'lotto', name: 'Lotto', totalNumbers: 49, drawSize: 6, color: 'text-yellow-500' },
    { id: 'mini', name: 'Mini Lotto', totalNumbers: 42, drawSize: 5, color: 'text-blue-400' },
    { 
      id: 'euro', 
      name: 'Eurojackpot', 
      totalNumbers: 50, 
      drawSize: 5, 
      bonusTotalNumbers: 12, 
      bonusDrawSize: 2, 
      color: 'text-orange-500' 
    }
  ];

  /**
   * EXPERT KNOWLEDGE BASE (2021-2025 Trends)
   * Specific to Polish Lotto (1-49).
   */
  private readonly EXPERT_DATA_LOTTO = {
    hot: [4, 30, 14, 2, 44, 24],
    cold: [43, 48, 33, 1],
    pairs: [[4, 30], [17, 21], [24, 29], [15, 25]]
  };

  /**
   * EXPERT KNOWLEDGE BASE (2021-2025 Trends)
   * Specific to Mini Lotto (1-42).
   */
  private readonly EXPERT_DATA_MINI = {
    hot: [21, 28, 4, 36, 30, 6],
    cold: [14, 20, 25],
    pairs: [[21, 30], [6, 28], [28, 36]]
  };

  /**
   * EXPERT KNOWLEDGE BASE (2021-2026 Trends)
   * Specific to Eurojackpot (5/50 + 2/12).
   */
  private readonly EXPERT_DATA_EURO = {
    // Main Numbers (1-50)
    hotMain: [34, 49, 20, 7, 35],
    coldMain: [48, 2, 5, 23],

    // Euro Numbers (1-12)
    hotBonus: [3, 8, 5], 
    // 11 and 12 are statistically colder due to being added only in 2022

    pairs: [[34, 49], [7, 35]]
  };

  // MOCK DATA FOR "RECENT DRAWS" TAB
  // In a real app, this would come from an API.
  private readonly MOCK_PAST_DRAWS: Record<GameType, PastDraw[]> = {
      lotto: [
          { date: '2024-05-18', numbers: [2, 14, 22, 29, 35, 44], bonusNumbers: [] },
          { date: '2024-05-16', numbers: [4, 8, 15, 23, 30, 41], bonusNumbers: [] },
          { date: '2024-05-14', numbers: [1, 19, 24, 28, 33, 49], bonusNumbers: [] },
          { date: '2024-05-11', numbers: [5, 12, 17, 21, 36, 40], bonusNumbers: [] },
      ],
      mini: [
          { date: '2024-05-18', numbers: [6, 14, 21, 28, 36], bonusNumbers: [] },
          { date: '2024-05-17', numbers: [2, 9, 15, 30, 41], bonusNumbers: [] },
          { date: '2024-05-16', numbers: [5, 11, 22, 33, 39], bonusNumbers: [] },
      ],
      euro: [
          { date: '2024-05-17', numbers: [3, 18, 22, 34, 49], bonusNumbers: [3, 5] },
          { date: '2024-05-14', numbers: [1, 7, 15, 35, 44], bonusNumbers: [8, 10] },
          { date: '2024-05-10', numbers: [5, 12, 29, 33, 41], bonusNumbers: [1, 12] },
      ]
  };

  // State
  activeGameId = signal<GameType>('lotto');

  // DEFAULT IS NOW EXPERT TREND
  dataSource = signal<DataSource>('expert_trend');

  manualHotNumbers = signal<Set<number>>(new Set());

  // Custom Data State
  customDataCounts = signal<Record<number, number>>({});
  customDataPairs = signal<number[][]>([]); // NEW: Store correlations from import
  customDataTotalDraws = signal<number>(0);

  stats = signal<NumberStat[]>([]);

  savedCoupons = signal<Coupon[]>([]);

  // Holds the list of past draws (starts with mock, can be added to)
  pastDraws = signal<Record<GameType, PastDraw[]>>(this.MOCK_PAST_DRAWS);

  activeGameConfig = computed(() => 
    this.games.find(g => g.id === this.activeGameId())!
  );

  // Computed for correlation/pairs display
  topPairs = computed(() => {
    if (this.dataSource() === 'expert_trend') {
       if (this.activeGameId() === 'lotto') return this.EXPERT_DATA_LOTTO.pairs;
       if (this.activeGameId() === 'mini') return this.EXPERT_DATA_MINI.pairs;
       if (this.activeGameId() === 'euro') return this.EXPERT_DATA_EURO.pairs;
    }
    if (this.dataSource() === 'custom_import') {
        return this.customDataPairs();
    }
    return [];
  });

  currentPastDraws = computed(() => {
      return this.pastDraws()[this.activeGameId()];
  });

  constructor() {
    effect(() => {
        this.calculateStats();
    });
  }

  setGame(gameId: GameType) {
    this.activeGameId.set(gameId);
    this.manualHotNumbers.set(new Set()); 
  }

  setDataSource(source: DataSource) {
    this.dataSource.set(source);
  }

  addManualDraw(numbers: number[], bonusNumbers: number[]) {
      const today = new Date().toISOString().split('T')[0];
      const newDraw: PastDraw = {
          date: today,
          numbers: [...numbers].sort((a,b) => a-b),
          bonusNumbers: [...bonusNumbers].sort((a,b) => a-b)
      };

      this.pastDraws.update(current => {
          const gameId = this.activeGameId();
          return {
              ...current,
              [gameId]: [newDraw, ...current[gameId]]
          };
      });

      // Also trigger a stats update if in manual/import mode (simplified logic)
      if (this.dataSource() !== 'expert_trend') {
          // In a real app, this would recalculate complex stats
          this.calculateStats(); 
      }
  }

  toggleManualHotNumber(num: number) {
    const current = new Set(this.manualHotNumbers());
    if (current.has(num)) {
      current.delete(num);
    } else {
      current.add(num);
    }
    this.manualHotNumbers.set(current);
  }

  // PARSER for User Data
  processImportedData(text: string): boolean {
    const counts: Record<number, number> = {};
    const pairCounts: Record<string, number> = {};
    let validDraws = 0;
    const lines = text.split('\n');

    const regex = /(\d{1,2}[,.\s]\d{1,2}[,.\s]\d{1,2}[,.\s]\d{1,2}[,.\s]\d{1,2})/; 

    for (const line of lines) {
        const match = line.match(regex);
        if (match) {
            const numbersPart = match[0];
            const nums = numbersPart.split(/[,.\s]+/).map(n => parseInt(n.trim()));
            const config = this.activeGameConfig();
            const validNums = nums.filter(n => !isNaN(n) && n >= 1 && n <= config.totalNumbers);
            const sortedNums = [...validNums].sort((a, b) => a - b);

            if (validNums.length >= 5) { 
                validDraws++;
                // Count individual numbers
                validNums.forEach(n => {
                    counts[n] = (counts[n] || 0) + 1;
                });

                // Calculate Pairs (Correlations)
                for (let i = 0; i < sortedNums.length; i++) {
                    for (let j = i + 1; j < sortedNums.length; j++) {
                        const key = `${sortedNums[i]}-${sortedNums[j]}`;
                        pairCounts[key] = (pairCounts[key] || 0) + 1;
                    }
                }
            }
        }
    }

    if (validDraws > 0) {
        this.customDataCounts.set(counts);
        this.customDataTotalDraws.set(validDraws);

        // Process top pairs from import
        const sortedPairs = Object.entries(pairCounts)
            .sort(([, countA], [, countB]) => countB - countA)
            .slice(0, 4)
            .map(([key]) => key.split('-').map(Number));

        this.customDataPairs.set(sortedPairs);

        this.setDataSource('custom_import');
        return true;
    }
    return false;
  }

  private calculateStats() {
    switch (this.dataSource()) {
      case 'expert_trend':
        this.loadExpertTrendStats();
        break;
      case 'manual':
        this.applyManualStats();
        break;
      case 'custom_import':
        this.loadCustomImportStats();
        break;
      // Default fallback to expert if something goes wrong
      default:
        this.loadExpertTrendStats();
        break;
    }
  }

  private loadExpertTrendStats() {
    const config = this.activeGameConfig();
    const statsArray: NumberStat[] = [];

    const baseCount = 50;

    for (let i = 1; i <= config.totalNumbers; i++) {
        let count = baseCount;
        let status: 'hot' | 'neutral' | 'cold' = 'neutral';

        if (this.activeGameId() === 'lotto') {
            if (this.EXPERT_DATA_LOTTO.hot.includes(i)) { count = 100; status = 'hot'; }
            else if (this.EXPERT_DATA_LOTTO.cold.includes(i)) { count = 10; status = 'cold'; }
        } else if (this.activeGameId() === 'mini') {
            if (this.EXPERT_DATA_MINI.hot.includes(i)) { count = 100; status = 'hot'; }
            else if (this.EXPERT_DATA_MINI.cold.includes(i)) { count = 10; status = 'cold'; }
        } else if (this.activeGameId() === 'euro') {
             if (this.EXPERT_DATA_EURO.hotMain.includes(i)) { count = 100; status = 'hot'; }
             else if (this.EXPERT_DATA_EURO.coldMain.includes(i)) { count = 10; status = 'cold'; }
        }

        // Add noise to make charts look alive but keeping the trend
        if (status === 'neutral') count += Math.floor(Math.random() * 20) - 10;

        statsArray.push({
            number: i,
            count: count,
            frequency: count / 100,
            status: status
        });
    }

    statsArray.sort((a, b) => b.count - a.count);
    this.stats.set(statsArray.sort((a, b) => a.number - b.number));
  }

  private loadCustomImportStats() {
    const config = this.activeGameConfig();
    const statsArray: NumberStat[] = [];
    const counts = this.customDataCounts();
    const total = this.customDataTotalDraws();

    for (let i = 1; i <= config.totalNumbers; i++) {
        const count = counts[i] || 0;
        statsArray.push({
            number: i,
            count: count,
            frequency: total > 0 ? count / total : 0,
            status: 'neutral'
        });
    }
    statsArray.sort((a, b) => b.count - a.count);
    this.assignHotColdStatus(statsArray, config.totalNumbers);
    this.stats.set(statsArray.sort((a, b) => a.number - b.number));
  }

  private applyManualStats() {
    const config = this.activeGameConfig();
    const statsArray: NumberStat[] = [];
    const manualHot = this.manualHotNumbers();

    for (let i = 1; i <= config.totalNumbers; i++) {
        statsArray.push({
            number: i,
            count: manualHot.has(i) ? 100 : Math.floor(Math.random() * 50),
            frequency: 0,
            status: manualHot.has(i) ? 'hot' : 'neutral'
        });
    }
    statsArray.sort((a, b) => b.count - a.count);
    this.assignHotColdStatus(statsArray, config.totalNumbers, manualHot);
    this.stats.set(statsArray.sort((a, b) => a.number - b.number));
  }

  private assignHotColdStatus(statsArray: NumberStat[], totalNumbers: number, manualHot?: Set<number>) {
    const hotThreshold = Math.floor(totalNumbers * 0.2);
    const coldThreshold = Math.floor(totalNumbers * 0.8);

    statsArray.forEach((stat, index) => {
      if (manualHot && manualHot.has(stat.number)) {
          stat.status = 'hot';
      } else {
        if (index < hotThreshold && (!manualHot || !manualHot.has(stat.number))) stat.status = 'hot';
        else if (index > coldThreshold) stat.status = 'cold';
        else stat.status = 'neutral';
      }
    });
  }

  generateSmartPrediction(): { numbers: number[], bonusNumbers: number[], logic: string[] } {
    const config = this.activeGameConfig();
    const allStats = [...this.stats()].sort((a, b) => b.count - a.count);

    const selection = new Set<number>();
    const bonusSelection = new Set<number>();
    const logic: string[] = [];

    // 1. MAIN NUMBERS LOGIC
    const hotPool = allStats.filter(s => s.status === 'hot');
    const coldPool = allStats.filter(s => s.status === 'cold');
    const neutralPool = allStats.filter(s => s.status === 'neutral');

    let hotTarget = Math.ceil(config.drawSize * 0.5);

    // Logic is primarily EXPERT now
    if (this.dataSource() === 'expert_trend') {
        if (this.activeGameId() === 'lotto') {
            logic.push(`Lotto Expert: Analiza 2021-2025.`);
            this.tryAddPair(selection, this.EXPERT_DATA_LOTTO.pairs, logic);
        } else if (this.activeGameId() === 'mini') {
            logic.push(`Mini Expert: 5-letni trend.`);
            this.tryAddPair(selection, this.EXPERT_DATA_MINI.pairs, logic);
        } else if (this.activeGameId() === 'euro') {
            logic.push(`Eurojackpot Expert: Trend (34, 49, 20...).`);
            this.tryAddPair(selection, this.EXPERT_DATA_EURO.pairs, logic);
        }
        hotTarget = Math.max(0, hotTarget - selection.size);
    } else {
         logic.push(`Strategia użytkownika (Import/Manual).`);
         // Use correlations from import if available
         if (this.dataSource() === 'custom_import' && this.customDataPairs().length > 0) {
            this.tryAddPair(selection, this.customDataPairs(), logic);
         }
    }

    // Fill Main
    this.fillFromPool(selection, hotPool, config.drawSize - 1); // Heavily favor hot
    this.fillFromPool(selection, coldPool, config.drawSize); // Add maybe 1 cold
    this.fillFromPool(selection, neutralPool, config.drawSize); // Fill rest
    // Final check
    while (selection.size < config.drawSize) {
        const r = Math.floor(Math.random() * config.totalNumbers) + 1;
        selection.add(r);
    }

    // 2. BONUS NUMBERS LOGIC (Only for Euro)
    if (config.bonusTotalNumbers && config.bonusDrawSize) {
        if (this.dataSource() === 'expert_trend' && this.activeGameId() === 'euro') {
            logic.push(`Euro Bonus: Priorytet (3, 8, 5) - "Królowie Bonusów".`);

            // Try adding hot bonus numbers
            const hotBonus = this.EXPERT_DATA_EURO.hotBonus;
            // 70% chance to pick at least one hot bonus
            if (Math.random() < 0.7) {
                const pick = hotBonus[Math.floor(Math.random() * hotBonus.length)];
                bonusSelection.add(pick);
            }
        }

        // Fill rest of bonus
        let safeCounter = 0;
        while (bonusSelection.size < config.bonusDrawSize && safeCounter < 100) {
            safeCounter++;
            const r = Math.floor(Math.random() * config.bonusTotalNumbers) + 1;

            // EXPERT LOGIC:
            // Penalize 11 and 12 in Eurojackpot Expert Mode because they were added in 2022
            if (this.dataSource() === 'expert_trend' && this.activeGameId() === 'euro') {
                if ((r === 11 || r === 12) && Math.random() > 0.15) {
                    continue; 
                }
            }
            bonusSelection.add(r);
        }
    }

    return {
      numbers: Array.from(selection).sort((a, b) => a - b),
      bonusNumbers: Array.from(bonusSelection).sort((a, b) => a - b),
      logic
    };
  }

  private tryAddPair(selection: Set<number>, pairs: number[][], logic: string[]) {
      if (Math.random() > 0.3 && pairs.length > 0) {
        const pair = pairs[Math.floor(Math.random() * pairs.length)];
        // Only add if not already present
        if (!pair.some(p => selection.has(p))) {
            pair.forEach(n => selection.add(n));
            logic.push(`Wykryto silną parę: (${pair.join(' i ')}).`);
        }
      }
  }

  private fillFromPool(selection: Set<number>, pool: NumberStat[], targetSize: number) {
      if (selection.size >= targetSize) return;
      const shuffled = [...pool].sort(() => 0.5 - Math.random());

      for (const stat of shuffled) {
          if (selection.size >= targetSize) break;
          selection.add(stat.number);
      }
  }

  saveCoupon(numbers: number[], bonusNumbers: number[], type: 'ai' | 'manual') {
    const newCoupon: Coupon = {
      id: crypto.randomUUID(),
      type: type,
      date: new Date(),
      gameId: this.activeGameId(),
      gameName: this.activeGameConfig().name,
      numbers: [...numbers].sort((a, b) => a - b),
      bonusNumbers: [...bonusNumbers].sort((a, b) => a - b),
      drawResult: null,
      bonusDrawResult: null,
      matches: null,
      bonusMatches: null,
      isRealCheck: false
    };
    this.savedCoupons.update(prev => [newCoupon, ...prev]);
  }

  checkCouponResult(couponId: string) {
    const config = this.activeGameConfig();
    const draw = this.generateRandomDraw(config.totalNumbers, config.drawSize).sort((a, b) => a - b);
    let bonusDraw: number[] = [];
    if (config.bonusTotalNumbers && config.bonusDrawSize) {
        bonusDraw = this.generateRandomDraw(config.bonusTotalNumbers, config.bonusDrawSize).sort((a, b) => a - b);
    }

    this.savedCoupons.update(coupons => coupons.map(c => {
      if (c.id === couponId) {
        const matches = c.numbers.filter(n => draw.includes(n)).length;
        const bonusMatches = c.bonusNumbers.filter(n => bonusDraw.includes(n)).length;
        return { 
            ...c, 
            drawResult: draw, 
            bonusDrawResult: bonusDraw, 
            matches, 
            bonusMatches,
            isRealCheck: false 
        };
      }
      return c;
    }));
  }

  checkCouponsAgainstRealNumbers(winningNumbers: number[], bonusWinningNumbers: number[] = []) {
    const sortedWinning = [...winningNumbers].sort((a, b) => a - b);
    const sortedBonus = [...bonusWinningNumbers].sort((a, b) => a - b);
    const currentGameId = this.activeGameId();

    this.savedCoupons.update(coupons => coupons.map(c => {
      if (c.gameId === currentGameId) {
        const matches = c.numbers.filter(n => sortedWinning.includes(n)).length;
        const bonusMatches = c.bonusNumbers.filter(n => sortedBonus.includes(n)).length;
        return { 
          ...c, 
          drawResult: sortedWinning, 
          bonusDrawResult: sortedBonus,
          matches,
          bonusMatches,
          isRealCheck: true 
        };
      }
      return c;
    }));
  }

  clearHistory() {
    this.savedCoupons.set([]);
  }

  private pickRandomFrom(pool: NumberStat[]): NumberStat {
    if (pool.length === 0) return this.stats()[Math.floor(Math.random() * this.stats().length)];
    const idx = Math.floor(Math.random() * pool.length);
    return pool[idx];
  }

  private generateRandomDraw(total: number, size: number): number[] {
    const numbers = new Set<number>();
    while (numbers.size < size) {
      numbers.add(Math.floor(Math.random() * total) + 1);
    }
    return Array.from(numbers);
  }
}

import { Component, signal, inject, computed, effect } from '@angular/core';
import { CommonModule, DOCUMENT } from '@angular/common';
import { LottoStatsService, GameType } from './services/lotto-stats.service';
import { GeminiService } from './services/gemini.service';
import { HistogramComponent } from './components/histogram.component';

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [CommonModule, HistogramComponent],
  templateUrl: './app.component.html'
})
export class AppComponent {
  lottoService = inject(LottoStatsService);
  geminiService = inject(GeminiService);

  // UI State - Added 'results'
  currentView = signal<'analyze' | 'history' | 'settings' | 'results'>('analyze');
  isManualMode = signal(false);
  visualizationMode = signal<'bars' | 'heatmap'>('bars');

  // Theme & Fullscreen State
  isDarkMode = signal(true);
  isFullscreen = signal(false);

  // History Filter State
  historyFilter = signal<'all' | GameType>('all');

  // Real Check Mode State (in History)
  isCheckMode = signal(false);
  winningNumbersSelection = signal<Set<number>>(new Set());
  winningBonusSelection = signal<Set<number>>(new Set());

  // Results Tab State
  isAddingResult = signal(false);
  newResultSelection = signal<Set<number>>(new Set());
  newResultBonusSelection = signal<Set<number>>(new Set());

  // Import Data State
  importText = signal('');
  importSuccess = signal(false);

  // AI Logic State
  loading = signal(false);
  prediction = signal<number[]>([]);
  predictionBonus = signal<number[]>([]);
  logicSteps = signal<string[]>([]);
  aiExplanation = signal<string>('');

  // Manual Entry State
  manualNumbers = signal<Set<number>>(new Set());
  manualBonusNumbers = signal<Set<number>>(new Set());

  // Feedback state
  linkCopied = signal(false);

  constructor() {
    // Effect to handle Dark Mode class on HTML element
    effect(() => {
      const html = document.documentElement;
      if (this.isDarkMode()) {
        html.classList.add('dark');
      } else {
        html.classList.remove('dark');
      }
    });

    // Listen to fullscreen changes to update state if user uses ESC key
    document.addEventListener('fullscreenchange', () => {
      this.isFullscreen.set(!!document.fullscreenElement);
    });
  }

  // Computed helper for MAIN grid generation
  gridNumbers = computed(() => {
    return Array.from({ length: this.lottoService.activeGameConfig().totalNumbers }, (_, i) => i + 1);
  });

  // Computed helper for BONUS grid generation (Eurojackpot)
  bonusGridNumbers = computed(() => {
    const max = this.lottoService.activeGameConfig().bonusTotalNumbers || 0;
    return Array.from({ length: max }, (_, i) => i + 1);
  });

  isManualComplete = computed(() => {
    const config = this.lottoService.activeGameConfig();
    const mainOk = this.manualNumbers().size === config.drawSize;
    const bonusOk = config.bonusDrawSize ? this.manualBonusNumbers().size === config.bonusDrawSize : true;
    return mainOk && bonusOk;
  });

  // For Checking Mode
  isWinningSelectionComplete = computed(() => {
    const config = this.lottoService.activeGameConfig();
    const mainOk = this.winningNumbersSelection().size === config.drawSize;
    const bonusOk = config.bonusDrawSize ? this.winningBonusSelection().size === config.bonusDrawSize : true;
    return mainOk && bonusOk;
  });

  // For New Result Mode
  isNewResultComplete = computed(() => {
    const config = this.lottoService.activeGameConfig();
    const mainOk = this.newResultSelection().size === config.drawSize;
    const bonusOk = config.bonusDrawSize ? this.newResultBonusSelection().size === config.bonusDrawSize : true;
    return mainOk && bonusOk;
  });

  // Filtered Coupons for History View
  filteredCoupons = computed(() => {
    const all = this.lottoService.savedCoupons();
    const filter = this.historyFilter();
    if (filter === 'all') return all;
    return all.filter(c => c.gameId === filter);
  });

  // Dashboard Stats Helpers
  topHotNumbers = computed(() => {
    return [...this.lottoService.stats()]
      .filter(s => s.status === 'hot')
      .sort((a, b) => b.count - a.count)
      .slice(0, 5);
  });

  topColdNumbers = computed(() => {
    return [...this.lottoService.stats()]
      .filter(s => s.status === 'cold')
      .sort((a, b) => a.count - b.count) // asc count
      .slice(0, 5);
  });

  oddEvenRatio = computed(() => {
    const hot = this.topHotNumbers();
    if (hot.length === 0) return '50/50';
    const odd = hot.filter(n => n.number % 2 !== 0).length;
    const even = hot.length - odd;
    return `${odd} (NP) / ${even} (P)`;
  });

  toggleTheme() {
    this.isDarkMode.update(v => !v);
  }

  toggleFullscreen() {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(err => {
        console.error(`Error attempting to enable fullscreen: ${err.message}`);
      });
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
      }
    }
  }

  toggleVisualizationMode(mode: 'bars' | 'heatmap') {
      this.visualizationMode.set(mode);
  }

  switchGame(gameId: GameType) {
    this.lottoService.setGame(gameId);
    this.resetState();
    this.isCheckMode.set(false);
    this.winningNumbersSelection.set(new Set());
    this.winningBonusSelection.set(new Set());
    this.newResultSelection.set(new Set());
    this.newResultBonusSelection.set(new Set());
  }

  toggleManualMode() {
    this.isManualMode.update(v => !v);
    this.manualNumbers.set(new Set());
    this.manualBonusNumbers.set(new Set());
  }

  // Toggle for the Real Check Mode in History
  toggleCheckMode() {
    this.isCheckMode.update(v => !v);
    this.winningNumbersSelection.set(new Set());
    this.winningBonusSelection.set(new Set());
  }

  toggleAddingResult() {
      this.isAddingResult.update(v => !v);
      this.newResultSelection.set(new Set());
      this.newResultBonusSelection.set(new Set());
  }

  setHistoryFilter(filter: 'all' | GameType) {
    this.historyFilter.set(filter);
  }

  toggleManualNumber(num: number) {
    const current = new Set(this.manualNumbers());
    const limit = this.lottoService.activeGameConfig().drawSize;
    if (current.has(num)) current.delete(num);
    else if (current.size < limit) current.add(num);
    this.manualNumbers.set(current);
  }

  toggleManualBonusNumber(num: number) {
    const current = new Set(this.manualBonusNumbers());
    const limit = this.lottoService.activeGameConfig().bonusDrawSize || 0;
    if (current.has(num)) current.delete(num);
    else if (current.size < limit) current.add(num);
    this.manualBonusNumbers.set(current);
  }

  toggleWinningNumber(num: number) {
    const current = new Set(this.winningNumbersSelection());
    const limit = this.lottoService.activeGameConfig().drawSize;
    if (current.has(num)) current.delete(num);
    else if (current.size < limit) current.add(num);
    this.winningNumbersSelection.set(current);
  }

  toggleWinningBonusNumber(num: number) {
    const current = new Set(this.winningBonusSelection());
    const limit = this.lottoService.activeGameConfig().bonusDrawSize || 0;
    if (current.has(num)) current.delete(num);
    else if (current.size < limit) current.add(num);
    this.winningBonusSelection.set(current);
  }

  toggleNewResultNumber(num: number) {
      const current = new Set(this.newResultSelection());
      const limit = this.lottoService.activeGameConfig().drawSize;
      if (current.has(num)) current.delete(num);
      else if (current.size < limit) current.add(num);
      this.newResultSelection.set(current);
  }

  toggleNewResultBonusNumber(num: number) {
      const current = new Set(this.newResultBonusSelection());
      const limit = this.lottoService.activeGameConfig().bonusDrawSize || 0;
      if (current.has(num)) current.delete(num);
      else if (current.size < limit) current.add(num);
      this.newResultBonusSelection.set(current);
  }

  saveNewResult() {
      if(this.isNewResultComplete()) {
          this.lottoService.addManualDraw(
              Array.from(this.newResultSelection()),
              Array.from(this.newResultBonusSelection())
          );
          this.isAddingResult.set(false);
          this.newResultSelection.set(new Set());
          this.newResultBonusSelection.set(new Set());
      }
  }

  saveManualCoupon() {
    if (this.isManualComplete()) {
      this.lottoService.saveCoupon(
          Array.from(this.manualNumbers()), 
          Array.from(this.manualBonusNumbers()),
          'manual'
      );
      this.currentView.set('history');
      this.isManualMode.set(false);
      this.manualNumbers.set(new Set());
      this.manualBonusNumbers.set(new Set());
    }
  }

  confirmRealCheck() {
    if (this.isWinningSelectionComplete()) {
      this.lottoService.checkCouponsAgainstRealNumbers(
          Array.from(this.winningNumbersSelection()),
          Array.from(this.winningBonusSelection())
      );
      this.isCheckMode.set(false);
      this.winningNumbersSelection.set(new Set());
      this.winningBonusSelection.set(new Set());
    }
  }

  onPasteResults(event: ClipboardEvent) {
    const clipboardData = event.clipboardData;
    const pastedText = clipboardData?.getData('text') || '';

    // Parse numbers
    const numbers = pastedText.split(/[\s,]+/)
      .map(s => parseInt(s.trim()))
      .filter(n => !isNaN(n));

    const config = this.lottoService.activeGameConfig();
    const newMain = new Set<number>();
    const newBonus = new Set<number>();

    // Simple logic: Fill Main first, then Bonus if Eurojackpot
    let i = 0;
    // Fill Main
    while(newMain.size < config.drawSize && i < numbers.length) {
        const n = numbers[i++];
        if (n >= 1 && n <= config.totalNumbers) newMain.add(n);
    }

    // Fill Bonus (if applicable)
    if (config.bonusTotalNumbers) {
        while(newBonus.size < (config.bonusDrawSize || 0) && i < numbers.length) {
            const n = numbers[i++];
             if (n >= 1 && n <= config.bonusTotalNumbers) newBonus.add(n);
        }
    }

    if (newMain.size > 0) this.winningNumbersSelection.set(newMain);
    if (newBonus.size > 0) this.winningBonusSelection.set(newBonus);
  }

  onImportTextChange(event: Event) {
    const target = event.target as HTMLTextAreaElement;
    this.importText.set(target.value);
  }

  processImport() {
    const success = this.lottoService.processImportedData(this.importText());
    if (success) {
        this.importSuccess.set(true);
        this.importText.set('');
        setTimeout(() => this.importSuccess.set(false), 3000);
        this.currentView.set('analyze');
    } else {
        alert('Nie udało się zaimportować danych. Sprawdź format.');
    }
  }

  private resetState() {
    this.prediction.set([]);
    this.predictionBonus.set([]);
    this.logicSteps.set([]);
    this.aiExplanation.set('');
    this.manualNumbers.set(new Set());
    this.manualBonusNumbers.set(new Set());
    this.isManualMode.set(false);
  }

  async generatePrediction() {
    this.loading.set(true);
    this.prediction.set([]); 
    this.predictionBonus.set([]);
    this.aiExplanation.set('');
    this.logicSteps.set([]);
    this.isManualMode.set(false);

    await new Promise(resolve => setTimeout(resolve, 600));

    const result = this.lottoService.generateSmartPrediction();

    this.prediction.set(result.numbers);
    this.predictionBonus.set(result.bonusNumbers);
    this.logicSteps.set(result.logic);
    this.loading.set(false);

    let contextString = result.numbers.join(', ');
    if (result.bonusNumbers.length > 0) {
        contextString += ` + (Bonus: ${result.bonusNumbers.join(', ')})`;
    }

    const explanation = await this.geminiService.explainPrediction(
      result.numbers, 
      this.lottoService.stats(),
      this.lottoService.activeGameConfig().name
    );

    this.aiExplanation.set(explanation);
  }

  saveCurrentPrediction() {
    if (this.prediction().length > 0) {
      this.lottoService.saveCoupon(this.prediction(), this.predictionBonus(), 'ai');
      this.currentView.set('history');
    }
  }

  clearHistory() {
    if (confirm('Czy na pewno chcesz usunąć całą historię kuponów?')) {
      this.lottoService.clearHistory();
    }
  }

  shareApp() {
    const url = window.location.href;
    const shareData = {
      title: 'Lotto Data Scientist',
      text: 'Sprawdź swoje szanse w Lotto z analizą AI!',
      url: url
    };
    if (navigator.share) {
      navigator.share(shareData).catch((err) => console.log('Error sharing:', err));
    } else {
      navigator.clipboard.writeText(url).then(() => {
        this.linkCopied.set(true);
        setTimeout(() => this.linkCopied.set(false), 2000);
      });
    }
  }
}

import { Injectable, signal, computed, effect } from '@angular/core';

export type GameType = 'lotto' | 'mini' | 'euro' | 'multi';
// Removed 'simulation' and 'real_history' to focus on the 5-year expert system
export type DataSource = 'manual' | 'custom_import' | 'expert_trend';

export interface GameConfig {
  id: GameType;
  name: string;
  totalNumbers: number;
  drawSize: number; // Number of balls drawn by machine
  // Optional configuration for bonus numbers (Eurojackpot)
  bonusTotalNumbers?: number;
  bonusDrawSize?: number;
  color: string;
}

export interface NumberStat {
  number: number;
  count: number;
  frequency: number; // percentage
  status: 'hot' | 'neutral' | 'cold';
}

export interface Coupon {
  id: string;
  type: 'ai' | 'manual';
  date: Date;
  gameId: GameType;
  gameName: string;
  numbers: number[];       // Main numbers
  bonusNumbers: number[];  // Euro numbers
  drawResult: number[] | null; // Main draw
  bonusDrawResult: number[] | null; // Bonus draw
  matches: number | null;
  bonusMatches: number | null;
  isRealCheck?: boolean;
}

export interface PastDraw {
  date: string;
  numbers: number[];
  bonusNumbers: number[];
}

